import React, { useRef, useState } from 'react';
import { Upload, FileSpreadsheet, CheckCircle, AlertCircle } from 'lucide-react';
import { parseExcelFile } from '../services/dataService';
import { FundSnapshot } from '../types';

interface FileUploadProps {
  onDataLoaded: (data: FundSnapshot) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataLoaded }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const handleFile = async (file: File) => {
    setIsProcessing(true);
    setError(null);
    setSuccess(null);

    try {
      const data = await parseExcelFile(file);
      if (data) {
        onDataLoaded(data);
        setSuccess(`Successfully imported ${data.fundName}`);
        setTimeout(() => setSuccess(null), 3000);
      }
    } catch (err) {
      setError("Failed to parse Excel file. Please check format.");
    } finally {
      setIsProcessing(false);
    }
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const onDragLeave = () => setIsDragging(false);

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  return (
    <div className="mb-8">
      <div 
        className={`
          border-2 border-dashed rounded-xl p-8 text-center transition-all cursor-pointer
          ${isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-gray-300 hover:border-indigo-400 hover:bg-gray-50'}
          ${isProcessing ? 'opacity-50 pointer-events-none' : ''}
        `}
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onDrop={onDrop}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept=".xlsx,.xls,.csv"
          onChange={(e) => e.target.files && handleFile(e.target.files[0])}
        />

        <div className="flex flex-col items-center gap-3">
          <div className="bg-white p-3 rounded-full shadow-sm">
            {isProcessing ? (
               <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
            ) : success ? (
              <CheckCircle className="text-green-500" size={32} />
            ) : error ? (
              <AlertCircle className="text-red-500" size={32} />
            ) : (
              <Upload className="text-indigo-600" size={32} />
            )}
          </div>

          <div className="space-y-1">
            <h3 className="text-sm font-semibold text-gray-900">
              {isProcessing ? 'Processing...' : 'Upload Portfolio Data'}
            </h3>
            <p className="text-xs text-gray-500">
              Drag & drop Excel file or click to browse
            </p>
          </div>
        </div>
      </div>

      {error && (
        <div className="mt-3 p-3 bg-red-50 text-red-700 text-sm rounded-lg flex items-center gap-2">
          <AlertCircle size={16} />
          {error}
        </div>
      )}

      {success && (
        <div className="mt-3 p-3 bg-green-50 text-green-700 text-sm rounded-lg flex items-center gap-2">
          <CheckCircle size={16} />
          {success}
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useEffect, useState } from 'react';
import { ArrowLeft, ExternalLink, TrendingUp, TrendingDown, Layers, Loader2 } from 'lucide-react';
import { FundSnapshot, StockPriceData } from '../types';
import { fetchStockPrice } from '../services/geminiService';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface StockDashboardProps {
  symbol: string;
  stockName: string;
  allFunds: FundSnapshot[];
  onBack: () => void;
}

const StockDashboard: React.FC<StockDashboardProps> = ({ symbol, stockName, allFunds, onBack }) => {
  const [priceData, setPriceData] = useState<StockPriceData | null>(null);
  const [loadingPrice, setLoadingPrice] = useState(false);

  useEffect(() => {
    const getPrice = async () => {
      setLoadingPrice(true);
      const data = await fetchStockPrice(symbol, stockName);
      setPriceData(data);
      setLoadingPrice(false);
    };
    getPrice();
  }, [symbol, stockName]);

  // 1. Find all funds that hold this stock (in their latest available month)
  // We need to group funds by Name first, then find the latest month for that fund.
  const uniqueFundNames = Array.from(new Set(allFunds.map(f => f.fundName)));

  const latestHoldings = uniqueFundNames.map(fundName => {
    // Get all snapshots for this fund
    const fundSnapshots = allFunds.filter(f => f.fundName === fundName);
    // Sort by month descending
    fundSnapshots.sort((a, b) => b.month.localeCompare(a.month));
    const latestSnapshot = fundSnapshots[0];

    if (!latestSnapshot) return null;

    const holding = latestSnapshot.holdings.find(h => h.symbol === symbol);
    if (!holding) return null;

    // Calculate 3-month trend for this fund
    const trendData = fundSnapshots.slice(0, 3).reverse().map(snap => {
      const h = snap.holdings.find(st => st.symbol === symbol);
      return {
        month: snap.month,
        quantity: h ? h.quantity : 0,
        percentage: h ? h.percentage : 0
      };
    });

    return {
      fundName,
      currentHolding: holding,
      trend: trendData
    };
  }).filter(item => item !== null);

  // Aggregate trend for chart (Total Quantity across all funds by month)
  // Get all unique months
  const allMonths = Array.from(new Set(allFunds.map(f => f.month))).sort();
  const aggregateTrend = allMonths.map(month => {
    let totalQty = 0;
    allFunds.filter(f => f.month === month).forEach(f => {
      const h = f.holdings.find(s => s.symbol === symbol);
      if (h) totalQty += h.quantity;
    });
    return { month, totalQty };
  });

  return (
    <div className="space-y-6 animate-fade-in">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
      >
        <ArrowLeft size={16} />
        Back to Fund List
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Header & Price Card */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h1 className="text-2xl font-bold text-gray-900">{stockName}</h1>
                <div className="flex items-center gap-2 text-gray-500 text-sm mt-1">
                  <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs">{symbol}</span>
                  <span>•</span>
                  <span>NSE/BSE</span>
                </div>
              </div>

              <div className="text-right">
                {loadingPrice ? (
                  <div className="flex items-center gap-2 text-indigo-600">
                    <Loader2 className="animate-spin" size={20} />
                    <span className="text-sm font-medium">Fetching Gemini Live Data...</span>
                  </div>
                ) : priceData ? (
                  <div>
                     {/* Because Gemini returns text, we display it carefully. Ideally we'd parse the number. */}
                     <div className="text-lg font-medium text-gray-900 max-w-md text-left md:text-right text-sm">
                       {priceData.price}
                     </div>
                     <div className="text-xs text-gray-400 mt-1">
                        Updated: {new Date(priceData.timestamp).toLocaleTimeString()}
                     </div>
                  </div>
                ) : (
                  <span className="text-red-400 text-sm">Failed to fetch price</span>
                )}
              </div>
            </div>

             {priceData && priceData.sources && priceData.sources.length > 0 && (
                <div className="mt-4 pt-4 border-t border-gray-100">
                  <h4 className="text-xs font-semibold text-gray-500 mb-2 uppercase tracking-wider">Sources (Grounding)</h4>
                  <div className="flex flex-wrap gap-2">
                    {priceData.sources.map((source, idx) => (
                      <a 
                        key={idx} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="flex items-center gap-1 text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded hover:bg-indigo-100 transition-colors"
                      >
                        <ExternalLink size={10} />
                        {source.title.substring(0, 20)}...
                      </a>
                    ))}
                  </div>
                </div>
              )}
          </div>

          {/* Aggregate Trend Chart */}
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
               <TrendingUp size={20} className="text-indigo-600" />
               Institutional Interest (Aggregate Qty)
             </h3>
             <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={aggregateTrend}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                    <XAxis dataKey="month" stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} />
                    <YAxis stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} />
                    <Tooltip 
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    />
                    <Line 
                      type="monotone" 
                      dataKey="totalQty" 
                      stroke="#4f46e5" 
                      strokeWidth={3} 
                      dot={{ r: 4, fill: '#4f46e5', strokeWidth: 2, stroke: '#fff' }} 
                    />
                  </LineChart>
                </ResponsiveContainer>
             </div>
          </div>
        </div>

        {/* Holdings List */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full">
          <div className="p-4 border-b border-gray-100 bg-gray-50">
            <h3 className="font-semibold text-gray-900 flex items-center gap-2">
              <Layers size={18} className="text-indigo-600" />
              Held by Funds
            </h3>
          </div>
          <div className="overflow-y-auto flex-1">
            {latestHoldings.length === 0 ? (
              <div className="p-8 text-center text-gray-500">No funds currently hold this stock.</div>
            ) : (
              <ul className="divide-y divide-gray-100">
                {latestHoldings.map((item, idx) => {
                  if (!item) return null;

                  // Calculate change from previous month in this specific fund
                  const prevMonthData = item.trend[item.trend.length - 2];
                  const currentQty = item.currentHolding.quantity;
                  const prevQty = prevMonthData ? prevMonthData.quantity : currentQty; // If no prev, assume 0 change
                  const diff = currentQty - prevQty;
                  const percentDiff = prevQty === 0 ? 100 : ((diff / prevQty) * 100).toFixed(1);

                  return (
                    <li key={idx} className="p-4 hover:bg-gray-50 transition-colors">
                      <div className="flex justify-between items-start mb-1">
                        <span className="font-medium text-sm text-gray-900">{item.fundName}</span>
                        {diff > 0 ? (
                          <span className="flex items-center text-xs text-green-600 bg-green-50 px-1.5 py-0.5 rounded">
                            <TrendingUp size={12} className="mr-1" />+{percentDiff}%
                          </span>
                        ) : diff < 0 ? (
                           <span className="flex items-center text-xs text-red-600 bg-red-50 px-1.5 py-0.5 rounded">
                            <TrendingDown size={12} className="mr-1" />{percentDiff}%
                          </span>
                        ) : (
                           <span className="text-xs text-gray-400 bg-gray-100 px-1.5 py-0.5 rounded">No Change</span>
                        )}
                      </div>
                      <div className="flex justify-between text-xs text-gray-500">
                         <span>Qty: {currentQty.toLocaleString()}</span>
                         <span>{item.currentHolding.percentage}% Portfolio</span>
                      </div>
                    </li>
                  );
                })}
              </ul>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StockDashboard;

import React, { useState, useMemo } from 'react';
import { ChevronRight, Search, TrendingUp, TrendingDown, RefreshCcw } from 'lucide-react';
import { FundSnapshot, StockHolding } from '../types';
import FileUpload from './FileUpload';

interface FundViewProps {
  funds: FundSnapshot[];
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
}

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock }) => {
  // Derive unique funds and months
  const uniqueFundNames = useMemo(() => Array.from(new Set(funds.map(f => f.fundName))), [funds]);

  const [selectedFundName, setSelectedFundName] = useState<string>(uniqueFundNames[0] || '');
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');

  // Update month selection when fund changes
  const availableMonths = useMemo(() => {
    return funds
      .filter(f => f.fundName === selectedFundName)
      .map(f => f.month)
      .sort()
      .reverse();
  }, [funds, selectedFundName]);

  // Set default month if not set
  React.useEffect(() => {
    if (availableMonths.length > 0 && !availableMonths.includes(selectedMonth)) {
      setSelectedMonth(availableMonths[0]);
    }
  }, [availableMonths, selectedMonth]);

  const currentSnapshot = funds.find(f => f.fundName === selectedFundName && f.month === selectedMonth);

  // Find previous month snapshot to calculate changes
  const previousMonth = availableMonths.length > 0 ? availableMonths[availableMonths.indexOf(selectedMonth) + 1] : null;
  const previousSnapshot = previousMonth ? funds.find(f => f.fundName === selectedFundName && f.month === previousMonth) : null;

  const getHoldingChange = (symbol: string): number => {
    if (!previousSnapshot) return 0;
    const prevHolding = previousSnapshot.holdings.find(h => h.symbol === symbol);
    if (!prevHolding) return 100; // New entry
    const currentHolding = currentSnapshot?.holdings.find(h => h.symbol === symbol);
    if (!currentHolding) return -100; // Exited
    return ((currentHolding.quantity - prevHolding.quantity) / prevHolding.quantity) * 100;
  };

  const filteredHoldings = currentSnapshot?.holdings.filter(h => 
    h.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    h.symbol.toLowerCase().includes(searchTerm.toLowerCase())
  ) || [];

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
           <p className="text-gray-500 text-sm">Track monthly portfolio changes</p>
        </div>
      </div>

      <FileUpload onDataLoaded={onFundDataAdded} />

