function App() {
  const [activeTab, setActiveTab] = useState<string>('DASHBOARD');
  const [funds, setFunds] = useState<FundSnapshot[]>(INITIAL_DATA);
  const [selectedStock, setSelectedStock] = useState<{symbol: string, name: string} | null>(null);

  // Handle Navigation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab !== 'STOCK_DETAIL') {
      setSelectedStock(null);
    }
  };

  const handleFundDataAdded = (newData: FundSnapshot) => {
    setFunds(prev => {
       // Avoid duplicates based on ID
       if (prev.find(f => f.id === newData.id)) return prev;
       return [...prev, newData];
    });
  };

  const handleSelectStock = (symbol: string, name: string) => {
    setSelectedStock({ symbol, name });
    setActiveTab('STOCK_DETAIL');
  };

  const renderContent = () => {
    if (activeTab === 'STOCK_DETAIL' && selectedStock) {
      return (
        <StockDashboard 
          symbol={selectedStock.symbol} 
          stockName={selectedStock.name}
          allFunds={funds}
          onBack={() => handleTabChange('FUND_DETAIL')}
        />
      );
    }

    switch (activeTab) {
      case 'DASHBOARD':
        return <DashboardOverview />;
      case 'FUND_DETAIL':
        return (
          <FundView 
            funds={funds} 
            onFundDataAdded={handleFundDataAdded} 
            onSelectStock={handleSelectStock}
          />
        );
      case 'STOCK_SEARCH':
        return (
          <StockSearch onSelectStock={handleSelectStock} />
        );
      default:
        return <DashboardOverview />;
    }
  };

  return (
    <Layout activeTab={activeTab === 'STOCK_DETAIL' ? 'FUND_DETAIL' : activeTab} onTabChange={handleTabChange}>
      {renderContent()}
    </Layout>
  );
}

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { StockPriceData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchStockPrice = async (symbol: string, stockName: string): Promise<StockPriceData | null> => {
  try {
    const prompt = `What is the current live stock price of ${stockName} (${symbol}) in NSE/BSE India? 
    Return the price, currency (INR), and percentage change today.
    Also provide the source URLs.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || '';

    // Extract grounding sources
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => chunk.web)
      .filter((web: any) => web)
      .map((web: any) => ({ uri: web.uri, title: web.title })) || [];

    // Simple heuristic parsing since we can't force JSON easily with Grounding on all models perfectly predictably
    // In a real app, we might use Function Calling to structure this data.
    // Here we will just return the text description and let the UI display it, 
    // or try a basic regex to find a number if needed.

    return {
      price: text, // Storing the full summary for now as "price" to ensure we capture the nuance
      currency: 'INR',
      timestamp: new Date().toISOString(),
      sources: sources
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return null;
  }
};

export const searchStocks = async (query: string): Promise<Array<{ symbol: string; name: string }>> => {
  try {
    const prompt = `Identify up to 5 Indian stock market companies (NSE/BSE) that match the search query "${query}". 
    Return the result as a strictly formatted JSON array of objects, where each object has "symbol" (e.g., RELIANCE) and "name" (e.g., Reliance Industries). 
    Ensure the symbols are standard NSE tickers.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              symbol: { type: Type.STRING },
              name: { type: Type.STRING },
            },
            required: ['symbol', 'name'],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Search Error:", error);
    return [];
  }
};

