import { FundSnapshot, StockHolding } from '../types';
import * as XLSX from 'xlsx';

// Mock Data Generation
const generateMockData = (): FundSnapshot[] => {
  const funds = ['Alpha Bluechip Fund', 'Beta Midcap Opportunities', 'Gamma Smallcap Discovery'];
  // Extended to 6 months for the new view
  const months = ['2023-08', '2023-09', '2023-10', '2023-11', '2023-12', '2024-01'];

  const stocks = [
    { symbol: 'RELIANCE', name: 'Reliance Industries Ltd' },
    { symbol: 'HDFCBANK', name: 'HDFC Bank Ltd' },
    { symbol: 'INFY', name: 'Infosys Ltd' },
    { symbol: 'TCS', name: 'Tata Consultancy Services' },
    { symbol: 'ICICIBANK', name: 'ICICI Bank Ltd' },
    { symbol: 'SBIN', name: 'State Bank of India' },
    { symbol: 'BHARTIARTL', name: 'Bharti Airtel Ltd' },
    { symbol: 'ITC', name: 'ITC Ltd' },
    { symbol: 'LICI', name: 'LIC India' },
    { symbol: 'TATAMOTORS', name: 'Tata Motors Ltd' },
    { symbol: 'LT', name: 'Larsen & Toubro Ltd' },
    { symbol: 'AXISBANK', name: 'Axis Bank Ltd' },
    { symbol: 'KOTAKBANK', name: 'Kotak Mahindra Bank' },
    { symbol: 'ULTRACEMCO', name: 'UltraTech Cement' },
    { symbol: 'ASIANPAINT', name: 'Asian Paints' },
  ];

  const data: FundSnapshot[] = [];

  funds.forEach((fund, fIndex) => {
    months.forEach((month, mIndex) => {
      const holdings: StockHolding[] = [];

      // Randomly select stocks for this fund
      stocks.forEach((stock, sIndex) => {
        // Deterministic randomness
        // Introduce some churn (buying/selling) by using mIndex
        const shouldHold = ((fIndex + sIndex) % 3 !== 0) || (mIndex > 3 && (sIndex % 2 === 0));

        if (shouldHold) { 
           // Simulate holding change
           const baseQty = 1000 * (sIndex + 1);
           const volatility = (Math.sin(mIndex + sIndex) * 200); 
           const quantity = Math.floor(baseQty + volatility);

           // Percentage fluctuates
           let percentage = (quantity / 20000 * 5); 

           // Ensure it's not too static
           percentage = percentage + (Math.cos(mIndex) * 0.2);

           holdings.push({
             symbol: stock.symbol,
             name: stock.name,
             quantity: quantity,
             percentage: Number(percentage.toFixed(2))
           });
        }
      });

      data.push({
        id: `${fund}-${month}`,
        fundName: fund,
        month: month,
        holdings: holdings
      });
    });
  });

  return data;
};

export const INITIAL_DATA: FundSnapshot[] = generateMockData();

// Excel Parsing Logic
export const parseExcelFile = async (file: File): Promise<FundSnapshot | null> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        const jsonData = XLSX.utils.sheet_to_json(sheet);

        // Simple Heuristic mapping
        // Expected columns: "Stock Name", "Symbol", "Quantity", "Percentage"
        // If not found, map generically

        const holdings: StockHolding[] = jsonData.map((row: any) => ({
          name: row['Stock Name'] || row['Name'] || 'Unknown',
          symbol: row['Symbol'] || row['Ticker'] || 'UNKNOWN',
          quantity: Number(row['Quantity'] || row['Qty'] || 0),
          percentage: Number(row['Percentage'] || row['% Assets'] || 0),
        })).filter(h => h.symbol !== 'UNKNOWN');

        // Infer Fund Name and Month from filename for demo purposes
        // "Alpha_Fund_Oct_2023.xlsx"
        const fileNameParts = file.name.split('.')[0].split('_');
        const fundName = fileNameParts[0] ? fileNameParts[0] + " Uploaded Fund" : "Uploaded Fund";
        const month = new Date().toISOString().slice(0, 7); // Default to current month

        const snapshot: FundSnapshot = {
          id: `${fundName}-${Date.now()}`,
          fundName: fundName,
          month: month,
          holdings: holdings
        };

        resolve(snapshot);

      } catch (error) {
        console.error("Excel parse error", error);
        reject(error);
      }
    };
    reader.onerror = (error) => reject(error);
    reader.readAsBinaryString(file);
  });
};

// --- Master Stock List Search Logic ---

interface StockApiItem {
  compname: string;
  s_name: string;
  fincode: number;
  stock_search: string;
}

// Module-level cache
let stockListCache: Array<{ symbol: string; name: string }> | null = null;
let stockListPromise: Promise<void> | null = null;

const ensureStockListLoaded = async () => {
  if (stockListCache) return;

  if (!stockListPromise) {
    stockListPromise = (async () => {
        try {
            const proxyUrl = "https://app-to-extract-holdings--shubhamgroverda.replit.app/api/extract-data";
            const targetUrl = "https://www.rupeevest.com/mf_stock_portfolio/get_search_data_stock";
            // The API expects `url` as a query parameter
            const response = await fetch(`${proxyUrl}?url=${targetUrl}`);
            const data = await response.json();

            if (data && Array.isArray(data.stock_data_search)) {
                 stockListCache = data.stock_data_search.map((item: StockApiItem) => {
                    // Extract symbol from "Name | Code | Symbol" format
                    // e.g., "ABB India Ltd. | 500002 | ABB"
                    const parts = item.stock_search.split('|');
                    const symbol = parts.length >= 3 ? parts[2].trim() : '';
                    return {
                        name: item.compname || item.s_name,
                        symbol: symbol
                    };
                 }).filter((s: {symbol: string, name: string}) => s.symbol && s.symbol.length > 0);
            } else {
                stockListCache = [];
            }
        } catch (err) {
            console.error("Error fetching stock list:", err);
            stockListCache = [];
        }
    })();
  }
  await stockListPromise;
};

export const searchStocksFromMasterList = async (query: string): Promise<Array<{ symbol: string; name: string }>> => {
    await ensureStockListLoaded();

    if (!stockListCache) return [];
    if (!query) return [];

    const lowerQ = query.toLowerCase();
    // Simple filter: symbol starts with or name includes
    // Limit to 20 results for performance
    return stockListCache.filter(s => 
        s.symbol.toLowerCase().startsWith(lowerQ) || 
        s.name.toLowerCase().includes(lowerQ)
    ).slice(0, 20);
};

import { GoogleGenAI, Type } from "@google/genai";
import { StockPriceData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchStockPrice = async (symbol: string, stockName: string): Promise<StockPriceData | null> => {
  try {
    const prompt = `What is the current live stock price of ${stockName} (${symbol}) in NSE/BSE India? 
    Return the price, currency (INR), and percentage change today.
    Just give the value and no other info and text.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || '';

    // Extract grounding sources
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => chunk.web)
      .filter((web: any) => web)
      .map((web: any) => ({ uri: web.uri, title: web.title })) || [];

    return {
      price: text,
      currency: 'INR',
      timestamp: new Date().toISOString(),
      sources: sources
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return null;
  }
};

export const searchFunds = async (query: string): Promise<Array<{ name: string; type: string }>> => {
  try {
    const prompt = `Identify up to 5 Indian Mutual Funds that match the search query "${query}". 
    Return the result as a strictly formatted JSON array of objects, where each object has "name" (e.g., SBI Bluechip Fund) and "type" (e.g., Large Cap).`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              type: { type: Type.STRING },
            },
            required: ['name', 'type'],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Fund Search Error:", error);
    return [];
  }
};

