function App() {
  const [activeTab, setActiveTab] = useState<string>('DASHBOARD');
  const [funds, setFunds] = useState<FundSnapshot[]>(INITIAL_DATA);
  const [selectedStock, setSelectedStock] = useState<{symbol: string, name: string} | null>(null);

  // Handle Navigation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab !== 'STOCK_DETAIL') {
      setSelectedStock(null);
    }
  };

  const handleFundDataAdded = (newData: FundSnapshot) => {
    setFunds(prev => {
       // Avoid duplicates based on ID
       if (prev.find(f => f.id === newData.id)) return prev;
       return [...prev, newData];
    });
  };

  const handleSelectStock = (symbol: string, name: string) => {
    setSelectedStock({ symbol, name });
    setActiveTab('STOCK_DETAIL');
  };

  const handleSelectFundFromDashboard = (fundName: string) => {
    console.log("Navigating to fund:", fundName);
    // Future implementation: Navigate to Fund Dashboard with this fund selected
    // For now, we can switch to the Fund Tracker tab
    setActiveTab('FUND_DETAIL');
  };

  const renderContent = () => {
    if (activeTab === 'STOCK_DETAIL' && selectedStock) {
      return (
        <StockDashboard 
          symbol={selectedStock.symbol} 
          stockName={selectedStock.name}
          onBack={() => handleTabChange('STOCK_SEARCH')}
          onSelectFund={handleSelectFundFromDashboard}
        />
      );
    }

    switch (activeTab) {
      case 'DASHBOARD':
        return <DashboardOverview />;
      case 'FUND_DETAIL':
        return (
          <FundView 
            funds={funds} 
            onFundDataAdded={handleFundDataAdded} 
            onSelectStock={handleSelectStock}
          />
        );
      case 'STOCK_SEARCH':
        return (
          <StockSearch onSelectStock={handleSelectStock} />
        );
      default:
        return <DashboardOverview />;
    }
  };

  return (
    <Layout activeTab={activeTab === 'STOCK_DETAIL' ? 'STOCK_SEARCH' : activeTab} onTabChange={handleTabChange}>
      {renderContent()}
    </Layout>
  );
}

