                       ) : '-'}
                    </td>
                  </tr>
                )) : (
                   <tr>
                     <td colSpan={4} className="px-6 py-8 text-center text-gray-400">
                       No funds found matching your search.
                     </td>
                   </tr>
                )}
              </tbody>
            </table>
          )}
        </div>

        {mfData && (
          <div className="p-4 bg-gray-50 text-xs text-gray-500 flex justify-between items-center border-t border-gray-200">
            <span>Showing {filteredHoldings.length} funds</span>
            <span>Data Source: Trendlyne</span>
          </div>
        )}
      </div>
    </div>
  );
};

