    if (!mfData) return [];

    let result = mfData.holdings.filter(h => 
      h.fundName.toLowerCase().includes(filterQuery.toLowerCase())
    );

    result.sort((a, b) => {
      // Sort based on the Latest Month's data (first column)
      // Note: Data is already sorted by date in 'history', so history[0] is latest

      // However, we need to match the actual month if there are gaps. 
      // For simplicity, we use the 'latest' property if it matches the first column month, 
      // otherwise we find it.
      const latestMonth = monthColumns[0];
      const dataA = a.history.find(h => h.month === latestMonth);
      const dataB = b.history.find(h => h.month === latestMonth);

      const valA = dataA ? (dataA[sortField] || 0) : 0;
      const valB = dataB ? (dataB[sortField] || 0) : 0;

      if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
      if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
