import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, Upload, Loader2 } from 'lucide-react';
import { FundSnapshot, StockHolding } from '../types';
import { parseExcelFile } from '../services/dataService';
import FundSearch from './FundSearch';

interface FundViewProps {
  funds: FundSnapshot[];
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: string | null;
}

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFundName, setSelectedFundName] = useState<string | null>(initialSelectedFund || null);
  const [searchTerm, setSearchTerm] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync with prop if it changes (e.g. from parent navigation)
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFundName(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // --- Mock Data Generator for Search Results (Demo Purpose) ---
  // If user selects a fund that isn't in uploaded data, generate it on the fly
  const displayFunds = useMemo(() => {
    if (!selectedFundName) return [];

    const existing = funds.filter(f => f.fundName === selectedFundName);
    if (existing.length > 0) return existing;

    // Generate mock data on the fly for demo if fund doesn't exist
    const months = ['2023-08', '2023-09', '2023-10', '2023-11', '2023-12', '2024-01'];
    const mockHoldingsPool = [
      { s: 'RELIANCE', n: 'Reliance Industries' }, { s: 'HDFCBANK', n: 'HDFC Bank' },
      { s: 'INFY', n: 'Infosys' }, { s: 'ITC', n: 'ITC Ltd' },
      { s: 'TCS', n: 'TCS' }, { s: 'SBIN', n: 'SBI' }
    ];

    return months.map((month, idx) => ({
      id: `${selectedFundName}-${month}`,
      fundName: selectedFundName,
      month: month,
      holdings: mockHoldingsPool.map((stock, sIdx) => ({
        symbol: stock.s,
        name: stock.n,
        quantity: 1000 * (sIdx + 1) + (idx * 50), // Slight increase each month
        percentage: 5 + (idx * 0.1) // Slight pct change
      }))
    }));
  }, [funds, selectedFundName]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          setSelectedFundName(data.fundName); // Switch to the uploaded fund immediately
        }
      } catch (err) {
        console.error(err);
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  // --- Matrix Logic ---
  const columns = useMemo(() => {
    const months = Array.from(new Set(displayFunds.map(f => f.month))).sort().reverse();
    return months.slice(0, 6);
  }, [displayFunds]);

  const pivotedData = useMemo(() => {
    const map = new Map<string, { name: string; holdings: Record<string, number> }>();
    columns.forEach(month => {
      const snapshot = displayFunds.find(f => f.month === month);
      if (snapshot) {
        snapshot.holdings.forEach(h => {
          if (!map.has(h.symbol)) {
            map.set(h.symbol, { name: h.name, holdings: {} });
          }
          const entry = map.get(h.symbol)!;
          entry.holdings[month] = h.percentage;
        });
      }
    });
    return Array.from(map.values());
  }, [displayFunds, columns]);

  const filteredRows = pivotedData.filter(row => 
    row.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header Area */}
      <div className="flex items-center justify-between pb-4 border-b border-gray-100">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isUploading}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
          >
            {isUploading ? <Loader2 size={16} className="animate-spin"/> : <Upload size={16} />}
            Upload Excel
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept=".xlsx,.xls,.csv"
            onChange={handleFileChange}
          />
        </div>
      </div>

      {!selectedFundName ? (
        <FundSearch onSelectFund={setSelectedFundName} />
      ) : (
        <div className="animate-fade-in space-y-4">
          <button 
            onClick={() => setSelectedFundName(null)}
            className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors mb-2"
          >
            <ArrowLeft size={16} />
            Search different fund
          </button>

          <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
            <div className="p-6 border-b border-gray-200 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-gray-900">{selectedFundName}</h3>
                <p className="text-sm text-gray-500">Portfolio composition & monthly changes</p>
              </div>

              <div className="relative w-full md:w-64">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-500" />
                </div>
                <input 
                  type="text" 
                  className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-2.5" 
                  placeholder="Search stocks in table..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left text-gray-500">
                <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                  <tr>
                    <th scope="col" className="px-6 py-4 min-w-[200px] sticky left-0 bg-gray-50 z-10 border-r border-gray-200 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">Stock Name</th>
                    {columns.map(month => (
                      <th key={month} scope="col" className="px-4 py-3 text-center whitespace-nowrap min-w-[100px]">
                        {month}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {filteredRows.length > 0 ? filteredRows.map((row, idx) => {
                     return (
                      <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors">
                        <td className="px-6 py-4 font-medium text-gray-900 sticky left-0 bg-white group-hover:bg-gray-50 border-r border-gray-200 z-10">
                          <button 
                            onClick={() => onSelectStock(Object.keys(row.holdings)[0] || '', row.name)}
                            className="text-indigo-600 hover:text-indigo-800 hover:underline text-left flex items-center gap-2"
                          >
                            {row.name}
                            <ArrowRight size={12} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                          </button>
                        </td>
                        {columns.map((month, colIdx) => {
                          const val = row.holdings[month];
                          const prevMonth = columns[colIdx + 1];
                          const prevVal = prevMonth ? row.holdings[prevMonth] : undefined;

                          let trendIcon = null;
                          let trendClass = "text-gray-900";

                          if (val !== undefined && prevVal !== undefined) {
                            if (val > prevVal) {
                               trendIcon = <TrendingUp size={12} className="text-green-500" />;
                               trendClass = "text-green-700 font-semibold";
                            } else if (val < prevVal) {
                               trendIcon = <TrendingDown size={12} className="text-red-500" />;
                               trendClass = "text-red-700 font-semibold";
                            }
                          }

                          return (
                            <td key={month} className="px-4 py-4 text-center">
                              {val !== undefined ? (
                                <div className={`flex items-center justify-center gap-1 ${trendClass}`}>
                                  {val.toFixed(2)}%
                                  {trendIcon}
                                </div>
                              ) : (
                                <span className="text-gray-300">-</span>
                              )}
                            </td>
                          );
                        })}
                      </tr>
                     )
                  }) : (
                    <tr>
                      <td colSpan={columns.length + 1} className="px-6 py-12 text-center text-gray-500">
                        No stocks found matching your criteria.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
            <div className="p-4 bg-gray-50 text-xs text-gray-500 text-center border-t border-gray-200">
               Values represent Percentage (%) of Assets Under Management (AUM).
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

