// Excel Parsing Logic
export const parseExcelFile = async (file: File): Promise<FundSnapshot | null> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        const jsonData = XLSX.utils.sheet_to_json(sheet);

        const holdings: StockHolding[] = jsonData.map((row: any) => ({
          name: row['Stock Name'] || row['Name'] || 'Unknown',
          symbol: row['Symbol'] || row['Ticker'] || 'UNKNOWN',
          quantity: Number(row['Quantity'] || row['Qty'] || 0),
          percentage: Number(row['Percentage'] || row['% Assets'] || 0),
        })).filter(h => h.symbol !== 'UNKNOWN');

        const fileNameParts = file.name.split('.')[0].split('_');
        const fundName = fileNameParts[0] ? fileNameParts[0] + " Uploaded Fund" : "Uploaded Fund";
        const month = new Date().toISOString().slice(0, 7); // Default to current month

        const snapshot: FundSnapshot = {
          id: `${fundName}-${Date.now()}`,
          fundName: fundName,
          month: month,
          holdings: holdings
        };

        resolve(snapshot);

      } catch (error) {
        console.error("Excel parse error", error);
        reject(error);
      }
    };
    reader.onerror = (error) => reject(error);
    reader.readAsBinaryString(file);
  });
};

// --- Master Stock List Search Logic ---

interface StockApiItem {
  compname: string;
  s_name: string;
  fincode: number;
  stock_search: string;
}

// Module-level cache
let stockListCache: Array<{ symbol: string; name: string }> | null = null;
let stockListPromise: Promise<void> | null = null;

const ensureStockListLoaded = async () => {
  if (stockListCache) return;

  if (!stockListPromise) {
    stockListPromise = (async () => {
        try {
            const targetUrl = "https://www.rupeevest.com/mf_stock_portfolio/get_search_data_stock";
            const data = await fetchFromProxy(targetUrl);

            if (data && Array.isArray(data.stock_data_search)) {
                 stockListCache = data.stock_data_search.map((item: StockApiItem) => {
                    const parts = item.stock_search.split('|');
                    const symbol = parts.length >= 3 ? parts[2].trim() : '';
                    return {
                        name: item.compname || item.s_name,
                        symbol: symbol
                    };
                 }).filter((s: {symbol: string, name: string}) => s.symbol && s.symbol.length > 0);
            } else {
                stockListCache = [];
            }
        } catch (err) {
            console.error("Error fetching stock list:", err);
            stockListCache = [];
        }
    })();
  }
  await stockListPromise;
};

export const searchStocksFromMasterList = async (query: string): Promise<Array<{ symbol: string; name: string }>> => {
    await ensureStockListLoaded();

    if (!stockListCache) return [];
    if (!query) return [];

    const lowerQ = query.toLowerCase();
    return stockListCache.filter(s => 
        s.symbol.toLowerCase().startsWith(lowerQ) || 
        s.name.toLowerCase().includes(lowerQ)
    ).slice(0, 20);
};

// --- Fund Portfolio Fetcher ---

export const fetchFundPortfolio = async (fundUrl: string): Promise<FundPortfolioHolding[] | null> => {
  try {
    const rawData = await fetchFromProxy(fundUrl, {
      attribute: 'data-holdings'
    });

    let jsonArray: any[] = [];
    if (typeof rawData === 'string') {
       try {
         jsonArray = JSON.parse(rawData);
       } catch (e) {
         console.error("Error parsing fund portfolio JSON string", e);
         // Try to handle potential double encoding or weird html entities if necessary
         return null;
       }
    } else if (Array.isArray(rawData)) {
       jsonArray = rawData;
    }

    if (!Array.isArray(jsonArray)) return null;

    // Map the array based on the provided schema:
    // Index 0: { name, nseCode, url, D, dcolor, V, vcolor, M, mcolor... }
    // Index 1: Sector
    // Index 2: Market Value
    // Index 4: % Holding
    // Index 5: Quantity
    // Index 6: Change Quantity
    // Index 7: Change Percentage
    // Index 8: History URL

    return jsonArray.map((item: any[]) => {
       const stockInfo = item[0] || {};
       return {
         stockName: stockInfo.name || "Unknown",
         stockSymbol: stockInfo.nseCode || "UNKNOWN",
         stockUrl: stockInfo.url || "",
         sector: item[1] || "",
         value: Number(item[2]) || 0,
         percentage: Number(item[4]) || 0,
         quantity: Number(item[5]) || 0,
         changeQuantity: Number(item[6]) || 0,
         changePercentage: Number(item[7]) || 0,
         historyUrl: item[8] || "",

         // Scores
         d: stockInfo.D,
         dColor: stockInfo.dcolor,
         v: stockInfo.V,
         vColor: stockInfo.vcolor,
         m: stockInfo.M,
         mColor: stockInfo.mcolor
       };
    });

  } catch (error) {
    console.error("Error fetching fund portfolio:", error);
    return null;
  }
};

// --- Live Stock Price Fetcher ---

export const fetchLiveStockPrice = async (symbol: string): Promise<StockPriceData | null> => {
  try {
    const targetUrl = `https://trendlyne.com/equity/${symbol}/stock-page/`;

    const htmlData = await fetchFromProxy(targetUrl, {
      attribute: 'class',
      attributeValue: ' stock_price_and_tools_container '
    });

    // Handle Proxy Response format (might be string, array, or object with rawValue)
    let htmlContent = "";
    if (typeof htmlData === 'string') {
        htmlContent = htmlData;
    } else if (Array.isArray(htmlData)) {
        htmlContent = htmlData.join(" ");
    } else if (htmlData && typeof htmlData === 'object') {
        htmlContent = htmlData.rawValue || JSON.stringify(htmlData);
    }

    if (!htmlContent) throw new Error("No HTML content received for Price");

    // Pass to Gemini for Parsing
    return await extractStockDataFromHtml(htmlContent);

  } catch (error) {
    console.error("Error fetching Live Stock Price:", error);
    return null;
  }
};

// --- Real-time Mutual Fund Holdings Fetcher ---

export const fetchMutualFundHoldingsForStock = async (symbol: string): Promise<StockMFAnalysis | null> => {
  try {
    const pkUrl = `https://trendlyne.com/equity/${symbol}/stock-page/`;

    // 1. Get Stock PK
    const pkData = await fetchFromProxy(pkUrl, { attribute: 'data-stock-pk' });
    console.log("Stock PK Response:", pkData);

    let stockPk = pkData;
    if (typeof pkData === 'object' && pkData !== null) {
       stockPk = pkData.rawValue || (Array.isArray(pkData) ? pkData[0] : null);
    }
    if (!stockPk) throw new Error("Could not fetch Stock PK");

    // 2. Get Stock Slug
    const slugData = await fetchFromProxy(pkUrl, { attribute: 'data-stockslugname' });
    console.log("Stock Slug Response:", slugData);

    let stockSlug = slugData;
    if (typeof slugData === 'object' && slugData !== null) {
        stockSlug = slugData.rawValue || (Array.isArray(slugData) ? slugData[0] : null);
    }
    if (!stockSlug) throw new Error("Could not fetch Stock Slug");

    // 3. Get Holdings Table
    const holdingsUrl = `https://trendlyne.com/equity/monthly-mutual-fund-share-holding/${stockPk}/${symbol}/latest/${stockSlug}/prune-etf/`;

    const rawHoldingsData = await fetchFromProxy(holdingsUrl, {
      attribute: 'class',
      attributeValue: 'table tl-dataTable JS_autoDataTables JS_export_btn full-width',
      tagName: 'table'
    });

    console.log("Raw Holdings Response:", rawHoldingsData);

    // Robust check for response structure
    let dataToParse = rawHoldingsData;
    if (!Array.isArray(rawHoldingsData)) {
         if (rawHoldingsData && Array.isArray(rawHoldingsData.data)) {
             dataToParse = rawHoldingsData.data;
         } else {
             // It might be that the proxy returns HTML string for table instead of JSON array. 
             // We can check if dataToParse is string. If so, we can't parse it easily without Gemini or Cheerio.
             // But for now, let's assume if it fails array check, it's null.
             console.warn("Expected array for holdings data but got:", rawHoldingsData);
             return null;
         }
    }

    // 4. Parse Data
    const mfHoldings: MutualFundHolding[] = dataToParse.map((item: any) => {
      const mfTotal = item["MF_Total:"];
      const fundName = mfTotal?.text || "Unknown Fund";
      const fundUrl = mfTotal?.href || "";

      // Extract dynamic month keys
      const history: MFHoldingHistory[] = [];
      const keys = Object.keys(item);

      const monthMap = new Map<string, Partial<MFHoldingHistory>>();

      keys.forEach(key => {
        // Regex to match "Dec-2025" pattern at start of key
        const match = key.match(/^([A-Za-z]{3}-\d{4})_(.+)$/);
        if (match) {
          const month = match[1];
          const type = match[2]; 

          if (!monthMap.has(month)) {
            monthMap.set(month, { month });
          }
          const entry = monthMap.get(month)!;

          if (type.includes("Shares Held")) {
            entry.sharesHeld = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("AUM (Cr)")) {
            entry.aum = parseFloat(String(item[key])) || 0;
          } else if (type.includes("Month Change %")) {
            entry.changePercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          } else if (type.includes("Month Change")) {
             entry.change = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("Hold %") || type.includes("AUM %")) {
             entry.aumPercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          }
        }
      });

      const historyArr = Array.from(monthMap.values()) as MFHoldingHistory[];
      historyArr.sort((a, b) => new Date(b.month).getTime() - new Date(a.month).getTime());

      return {
        fundName,
        fundUrl,
        latest: historyArr[0] || null,
        history: historyArr
      };
    });

    // 5. Aggregate History for Graph
    const aggMap = new Map<string, number>();
    mfHoldings.forEach(fund => {
      fund.history.forEach(h => {
        const current = aggMap.get(h.month) || 0;
        const shares = isNaN(h.sharesHeld) ? 0 : h.sharesHeld;
        aggMap.set(h.month, current + shares);
      });
    });

    const aggregateHistory = Array.from(aggMap.entries())
      .map(([month, totalShares]) => ({ month, totalShares }))
      .sort((a, b) => new Date(a.month).getTime() - new Date(b.month).getTime());

    return {
      stockSymbol: symbol,
      holdings: mfHoldings,
      aggregateHistory,
      sourceUrl: holdingsUrl
    };

  } catch (error) {
    console.error("Error fetching MF Holdings:", error);
    return null;
  }
};

import React, { useEffect, useState, useMemo } from 'react';
import { ArrowLeft, ExternalLink, TrendingUp, TrendingDown, Layers, Loader2, Search, Filter, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, BarChart2, RefreshCw } from 'lucide-react';
import { StockPriceData, StockMFAnalysis, MutualFundHolding, FundSearchResult } from '../types';
import { fetchLiveStockPrice, fetchMutualFundHoldingsForStock } from '../services/dataService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface StockDashboardProps {
  symbol: string;
  stockName: string;
  onBack: () => void;
  onSelectFund: (fund: FundSearchResult) => void;
}

type SortField = 'sharesHeld' | 'aum' | 'changePercent' | 'change' | 'aumPercent';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;

const StockDashboard: React.FC<StockDashboardProps> = ({ symbol, stockName, onBack, onSelectFund }) => {
  const [priceData, setPriceData] = useState<StockPriceData | null>(null);
  const [loadingPrice, setLoadingPrice] = useState(false);

  const [mfData, setMfData] = useState<StockMFAnalysis | null>(null);
  const [loadingMF, setLoadingMF] = useState(false);

  const [filterQuery, setFilterQuery] = useState('');

  // Sorting State
  const [sortField, setSortField] = useState<SortField>('sharesHeld');
  const [sortMonth, setSortMonth] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // Fetch Data on Mount
  useEffect(() => {
    const loadData = async () => {

      // 1. Fetch Live Price (via new API)
      setLoadingPrice(true);
      fetchLiveStockPrice(symbol).then(data => {
        setPriceData(data);
        setLoadingPrice(false);
      });

       // 2. Fetch MF Holdings (Trendlyne API chain)
      setLoadingMF(true);
      fetchMutualFundHoldingsForStock(symbol).then(data => {
        setMfData(data);
        setLoadingMF(false);
      });


    };
    loadData();
  }, [symbol, stockName]);

  // Determine available months from data
  const monthColumns = useMemo(() => {
    if (!mfData || mfData.holdings.length === 0) return [];
    const allMonths = Array.from(new Set(mfData.holdings.flatMap(h => h.history.map(hist => hist.month))));
    // Sort descending by date
    const sortedMonths = allMonths.sort((a, b) => new Date(b).getTime() - new Date(a).getTime()).slice(0, 3);

    // Set default sort month if not set
    if (!sortMonth && sortedMonths.length > 0) {
      setSortMonth(sortedMonths[0]);
    }

    return sortedMonths;
  }, [mfData, sortMonth]);

  // Filter and Sort Logic
  const filteredSortedHoldings = useMemo(() => {
    if (!mfData) return [];

    let result = mfData.holdings.filter(h => 
      h.fundName.toLowerCase().includes(filterQuery.toLowerCase())
    );

    const targetMonth = sortMonth || monthColumns[0];

    result.sort((a, b) => {
      const dataA = a.history.find(h => h.month === targetMonth);
      const dataB = b.history.find(h => h.month === targetMonth);

      // Handle missing data for specific months (treat as 0 or min value)
      const valA = dataA ? (dataA[sortField] || 0) : -Infinity;
      const valB = dataB ? (dataB[sortField] || 0) : -Infinity;

      if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
      if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [mfData, filterQuery, sortField, sortDirection, sortMonth, monthColumns]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredSortedHoldings.length / ITEMS_PER_PAGE);
  const paginatedHoldings = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredSortedHoldings.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredSortedHoldings, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
  }, [filterQuery, sortField, sortDirection, sortMonth]);

  const handleSort = (field: SortField, month: string) => {
    if (sortField === field && sortMonth === month) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortMonth(month);
      setSortDirection('desc');
    }
  };

  const SortIcon = ({ field, month }: { field: SortField, month: string }) => {
    const isActive = sortField === field && sortMonth === month;
    if (!isActive) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <ArrowUp size={12} className="ml-1 text-indigo-600" />
      : <ArrowDown size={12} className="ml-1 text-indigo-600" />;
  };

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="flex justify-between items-center">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
        >
          <ArrowLeft size={16} />
          Back to Search
        </button>
      </div>

      {/* Top Section: Price & Graph */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Price Card */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-3">
                  {stockName}
                  {mfData?.sourceUrl && (
                    <a 
                      href={mfData.sourceUrl} 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-gray-400 hover:text-indigo-600 transition-colors"
                      title="View full report on Trendlyne"
                    >
                      <ExternalLink size={20} />
                    </a>
                  )}
                </h1>
                <div className="flex items-center gap-2 text-gray-500 text-sm mt-1">
                  <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs">{symbol}</span>
                  <span>•</span>
                  <span>NSE/BSE</span>
                </div>
              </div>
              {priceData ? (
                <div className="text-right">
                    <div className="text-2xl font-bold text-gray-900">₹{priceData.current_price}</div>
                    <div className={`flex items-center justify-end gap-1 text-sm font-medium ${
                       priceData.todays_change_direction === 'up' ? 'text-green-600' : 
                       priceData.todays_change_direction === 'down' ? 'text-red-600' : 'text-gray-500'
                    }`}>
                        {priceData.todays_change_direction === 'up' ? <TrendingUp size={16} /> : 
                         priceData.todays_change_direction === 'down' ? <TrendingDown size={16} /> : null}
                        {priceData.todays_change_number} ({priceData.todays_change_percentage})
                    </div>
                    <div className="text-xs text-gray-400 mt-1 flex items-center justify-end gap-1">
                       <RefreshCw size={10} />
                       {priceData.last_updated}
                    </div>
                </div>
              ) : loadingPrice ? (
                 <div className="text-right">
                    <div className="h-8 w-24 bg-gray-100 animate-pulse rounded mb-1 ml-auto"></div>
                    <div className="h-4 w-16 bg-gray-100 animate-pulse rounded ml-auto"></div>
                 </div>
              ) : null}
            </div>

            {loadingPrice && (
              <div className="flex items-center gap-2 text-indigo-600 text-sm mt-2">
                <Loader2 className="animate-spin" size={16} /> Fetching live price...
              </div>
