export const fetchMutualFundHoldingsForStock = async (symbol: string): Promise<StockMFAnalysis | null> => {
  try {
    const pkUrl = `https://trendlyne.com/equity/${symbol}/stock-page/`;

    // 1. Get Stock PK
    const pkData = await fetchFromProxy(pkUrl, { attribute: 'data-stock-pk' });
    console.log("Stock PK Response:", pkData);

    let stockPk = pkData;
    if (typeof pkData === 'object' && pkData !== null) {
       stockPk = pkData.rawValue || (Array.isArray(pkData) ? pkData[0] : null);
    }
    if (!stockPk) throw new Error("Could not fetch Stock PK");

    // 2. Get Stock Slug
    const slugData = await fetchFromProxy(pkUrl, { attribute: 'data-stockslugname' });
    console.log("Stock Slug Response:", slugData);

    let stockSlug = slugData;
    if (typeof slugData === 'object' && slugData !== null) {
        stockSlug = slugData.rawValue || (Array.isArray(slugData) ? slugData[0] : null);
    }
    if (!stockSlug) throw new Error("Could not fetch Stock Slug");

    // 3. Get Holdings Table
    const holdingsUrl = `https://trendlyne.com/equity/monthly-mutual-fund-share-holding/${stockPk}/${symbol}/latest/${stockSlug}/prune-etf/`;

    const rawHoldingsData = await fetchFromProxy(holdingsUrl, {
      attribute: 'class',
      attributeValue: 'table tl-dataTable JS_autoDataTables JS_export_btn full-width',
      tagName: 'table'
    });

    console.log("Raw Holdings Response:", rawHoldingsData);

    // Robust check for response structure
    let dataToParse = rawHoldingsData;
    if (!Array.isArray(rawHoldingsData)) {
         if (rawHoldingsData && Array.isArray(rawHoldingsData.data)) {
             dataToParse = rawHoldingsData.data;
         } else {
             // It might be that the proxy returns HTML string for table instead of JSON array. 
             // We can check if dataToParse is string. If so, we can't parse it easily without Gemini or Cheerio.
             // But for now, let's assume if it fails array check, it's null.
             console.warn("Expected array for holdings data but got:", rawHoldingsData);
             return null;
         }
    }

    // 4. Parse Data
    const mfHoldings: MutualFundHolding[] = dataToParse.map((item: any) => {
      const mfTotal = item["MF_Total:"];
      const fundName = mfTotal?.text || "Unknown Fund";
      const fundUrl = mfTotal?.href || "";

      // Extract dynamic month keys
      const history: MFHoldingHistory[] = [];
      const keys = Object.keys(item);

      const monthMap = new Map<string, Partial<MFHoldingHistory>>();

      keys.forEach(key => {
        // Regex to match "Dec-2025" pattern at start of key
        const match = key.match(/^([A-Za-z]{3}-\d{4})_(.+)$/);
        if (match) {
          const month = match[1];
          const type = match[2]; 

          if (!monthMap.has(month)) {
            monthMap.set(month, { month });
          }
          const entry = monthMap.get(month)!;

          if (type.includes("Shares Held")) {
            entry.sharesHeld = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("AUM (Cr)")) {
            entry.aum = parseFloat(String(item[key])) || 0;
          } else if (type.includes("Month Change %")) {
            entry.changePercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          } else if (type.includes("Month Change")) {
             entry.change = parseInt(String(item[key]).replace(/,/g, ''), 10) || 0;
          } else if (type.includes("Hold %") || type.includes("AUM %")) {
             entry.aumPercent = parseFloat(String(item[key]).replace('%', '')) || 0;
          }
        }
      });

      const historyArr = Array.from(monthMap.values()) as MFHoldingHistory[];
      historyArr.sort((a, b) => new Date(b.month).getTime() - new Date(a.month).getTime());

      return {
        fundName,
        fundUrl,
        latest: historyArr[0] || null,
        history: historyArr
      };
    });

    // 5. Aggregate History for Graph
    const aggMap = new Map<string, number>();
    mfHoldings.forEach(fund => {
      fund.history.forEach(h => {
        const current = aggMap.get(h.month) || 0;
        const shares = isNaN(h.sharesHeld) ? 0 : h.sharesHeld;
        aggMap.set(h.month, current + shares);
      });
    });

    const aggregateHistory = Array.from(aggMap.entries())
      .map(([month, totalShares]) => ({ month, totalShares }))
      .sort((a, b) => new Date(a.month).getTime() - new Date(b.month).getTime());

    return {
      stockSymbol: symbol,
      holdings: mfHoldings,
      aggregateHistory,
      sourceUrl: holdingsUrl
    };

  } catch (error) {
    console.error("Error fetching MF Holdings:", error);
    return null;
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, Upload, Loader2, ExternalLink, History, ChevronLeft, ChevronRight, PieChart as PieIcon, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { FundSnapshot, FundSearchResult, FundPortfolioHolding, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { parseExcelFile, fetchFundPortfolio, fetchFundHoldingHistory } from '../services/dataService';
import FundSearch from './FundSearch';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FundViewProps {
  funds: FundSnapshot[]; // For uploaded files
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: FundSearchResult | null;
}

type SortField = 'percentage' | 'quantity' | 'changeQuantity' | 'changePercentage';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;
const CHART_COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4', '#3b82f6', '#64748b'];

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(initialSelectedFund || null);

  // Data States
  const [portfolioData, setPortfolioData] = useState<FundPortfolioHolding[] | null>(null);
  const [fundMeta, setFundMeta] = useState<FundMeta | null>(null);
  const [sectorData, setSectorData] = useState<SectorDistribution[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // History Data State
  const [historyCache, setHistoryCache] = useState<Record<string | number, { date: string, change: string }[]>>({});
  const [monthHeaders, setMonthHeaders] = useState<string[]>([]);
  const [loadingHistoryMap, setLoadingHistoryMap] = useState<Record<string | number, boolean>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('percentage');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // File Upload State
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync prop changes
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFund(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // Fetch API Data whenever selectedFund changes and has URL
  useEffect(() => {
    const loadData = async () => {
      if (!selectedFund || !selectedFund.url) {
          setPortfolioData(null);
          setFundMeta(null);
          setSectorData([]);
          setHistoryCache({});
          setMonthHeaders([]);
          return;
      }

      setLoading(true);
      try {
        const data = await fetchFundPortfolio(selectedFund.url);
        if (data) {
            setPortfolioData(data.holdings);
            setFundMeta(data.meta);
            setSectorData(data.sectorDistribution);
        } else {
            setPortfolioData([]);
            setFundMeta(null);
            setSectorData([]);
        }
      } catch (err) {
          console.error("Failed to load fund portfolio", err);
          setPortfolioData([]);
      } finally {
          setLoading(false);
      }
    };

    loadData();
  }, [selectedFund]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          // Switch to offline view logic (not fully implemented in this iteration, keeping focus on API)
          setSelectedFund({ name: data.fundName, url: '' });
          alert("Offline file viewing is limited in this demo mode. Please use the API flow.");
        }
      } catch (err) {
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  };

  const sortedData = useMemo(() => {
      if (!portfolioData) return [];

      let data = [...portfolioData];
      if (searchTerm) {
          const lower = searchTerm.toLowerCase();
          data = data.filter(item => 
              item.stockName.toLowerCase().includes(lower) || 
              item.stockSymbol.toLowerCase().includes(lower) ||
              item.sector.toLowerCase().includes(lower)
          );
      }

      return data.sort((a, b) => {
          const valA = a[sortField];
          const valB = b[sortField];
          if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
          if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
          return 0;
      });
  }, [portfolioData, searchTerm, sortField, sortDirection]);

  // Pagination Logic
  const totalPages = Math.ceil(sortedData.length / ITEMS_PER_PAGE);
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
    // Note: We don't clear historyCache here to preserve loaded data if user navigates back
  }, [searchTerm, sortField, sortDirection, selectedFund]);

  // --- Fetch History for Visible Rows ---
  useEffect(() => {
      if (!fundMeta?.fundPk || !paginatedData.length) return;

      const fetchVisibleHistory = async () => {
          // Identify items that need fetching (have stockPk but no cache)
          const itemsToFetch = paginatedData.filter(item => 
              item.stockPk && !historyCache[item.stockPk] && !loadingHistoryMap[item.stockPk]
          );

          if (itemsToFetch.length === 0) return;

          // Mark as loading
          setLoadingHistoryMap(prev => {
              const next = { ...prev };
              itemsToFetch.forEach(i => { if(i.stockPk) next[i.stockPk] = true; });
              return next;
          });

          // Fetch in batches to avoid overwhelming the browser/proxy
          const BATCH_SIZE = 5;
          for (let i = 0; i < itemsToFetch.length; i += BATCH_SIZE) {
              const batch = itemsToFetch.slice(i, i + BATCH_SIZE);

              await Promise.all(batch.map(async (item) => {
                  if (!item.stockPk) return;
                  try {
                      const history = await fetchFundHoldingHistory(fundMeta.fundPk!, item.stockPk);
                      if (history && history.length > 0) {
                          // Extract only necessary data: last 6 months
                          const processed = history.slice(0, 6).map(h => ({
                              date: h["Holding Date"],
                              change: h["1M Change %"]
                          }));

                          setHistoryCache(prev => ({
                              ...prev,
                              [item.stockPk!]: processed
                          }));

                          // Update headers if this is the first successful fetch or has newer data
                          // We use functional update to access latest headers state if needed, 
                          // but since headers are mostly static for a fund month, simple set is fine.
                          setMonthHeaders(prevHeaders => {
                              if (prevHeaders.length === 0 && processed.length > 0) {
                                  return processed.map(p => p.date);
                              }
                              return prevHeaders;
                          });
                      }
                  } catch (e) {
                      console.error(`Failed history fetch for ${item.stockSymbol}`, e);
                  } finally {
                      setLoadingHistoryMap(prev => {
                          const next = { ...prev };
                          if (item.stockPk) delete next[item.stockPk];
                          return next;
                      });
                  }
              }));
          }
      };

      fetchVisibleHistory();
  }, [paginatedData, fundMeta, historyCache, loadingHistoryMap]);


  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <div className="ml-1 text-indigo-600">▲</div>
      : <div className="ml-1 text-indigo-600">▼</div>;
  };

  const getDotColor = (val: string) => {
      if (val === 'positive') return 'bg-green-500';
      if (val === 'negative') return 'bg-red-500';
      return 'bg-yellow-400';
  };

  // Helper to ensure URL is absolute for the user link
  const getDisplayUrl = (url: string) => {
      if (!url) return '';
      if (url.startsWith('http')) return url;
      return `https://trendlyne.com${url}`;
  };

  const renderLegendText = (value: string, entry: any) => {
    const { color } = entry;
    return (
        <span className="text-gray-600 font-medium ml-1 text-xs">
            {value} <span className="text-gray-400 font-normal">({entry.payload.value}%)</span>
        </span>
    );
  };

  // Helper to get change color
  const getChangeColor = (val: string | undefined) => {
      if (!val) return 'text-gray-300';
      if (val.includes('-')) return 'text-red-500';
      return 'text-green-500';
  };

  return (
    <div className="space-y-6">
      {/* Header Area */}
      <div className="flex items-center justify-between pb-4 border-b border-gray-100">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
        </div>

        {/* Upload Excel Button - Hidden until implemented */}
        <div className="flex items-center gap-4" style={{ display: 'none' }}>
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isUploading}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
          >
            {isUploading ? <Loader2 size={16} className="animate-spin"/> : <Upload size={16} />}
            Upload Excel
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept=".xlsx,.xls,.csv"
            onChange={handleFileChange}
          />
        </div>
      </div>

      {!selectedFund ? (
        <FundSearch onSelectFund={(fund) => setSelectedFund(fund)} />
      ) : (
        <div className="animate-fade-in space-y-6">
          <button 
            onClick={() => { setSelectedFund(null); setPortfolioData(null); setFundMeta(null); setSectorData([]); setHistoryCache({}); setMonthHeaders([]); }}
            className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
          >
            <ArrowLeft size={16} />
            Search different fund
          </button>

          {/* Top Section: Fund Info & Pie Chart */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             {/* Fund Description Card */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col justify-between">
                <div>
                    <div className="flex items-start justify-between mb-4">
                    <div>
                        <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            {selectedFund.name}
                            {selectedFund.url && (
                                <a 
                                    href={getDisplayUrl(selectedFund.url)} 
                                    target="_blank" 
                                    rel="noreferrer"
                                    className="text-gray-400 hover:text-indigo-600 transition-colors"
                                    title="View full report on Trendlyne"
                                >
                                    <ExternalLink size={20} />
                                </a>
                            )}
                        </h3>
                        {loading ? (
                        <div className="h-6 w-32 bg-gray-100 animate-pulse rounded mt-2"></div>
                        ) : fundMeta?.category && (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 mt-2">
                            {fundMeta.category}
                        </span>
                        )}
                    </div>
                    </div>

                    <div className="prose prose-sm text-gray-500 max-w-none">
                    {loading ? (
                        <div className="space-y-2">
                        <div className="h-4 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-5/6 animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-4/6 animate-pulse"></div>
                        </div>
                    ) : (
                        <p>{fundMeta?.description || "No description available for this fund category."}</p>
                    )}
                    </div>
                </div>
             </div>

             {/* Sector Pie Chart */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col">
                <h4 className="font-semibold text-gray-800 mb-2 flex items-center gap-2 text-sm">
                   <PieIcon size={16} className="text-indigo-500"/>
                   Sector Allocation
                </h4>
                <div className="flex-1 min-h-[220px] relative">
                   {loading ? (
                      <div className="absolute inset-0 flex items-center justify-center">
                         <Loader2 className="animate-spin text-indigo-400" />
                      </div>
                   ) : sectorData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                         <PieChart>
                            <Pie
                               data={sectorData}
                               dataKey="value"
                               nameKey="name"
                               cx="50%"
                               cy="50%"
                               innerRadius={50}
                               outerRadius={80}
                               paddingAngle={2}
                            >
                               {sectorData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={CHART_COLORS[index % CHART_COLORS.length]} />
                               ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `${value}%`} />
                            <Legend 
                                layout="horizontal" 
                                verticalAlign="bottom" 
                                align="center" 
                                iconSize={8} 
                                wrapperStyle={{ fontSize: '10px', paddingTop: '10px' }}
                                formatter={renderLegendText}
                            />
                         </PieChart>
                      </ResponsiveContainer>
                   ) : (
                      <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                         No sector data available
                      </div>
                   )}
                </div>
             </div>
          </div>

          {/* Holdings Table Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
            <div className="p-6 border-b border-gray-200 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
              <div>
                <h3 className="text-lg font-bold text-gray-900">Portfolio Holdings</h3>
                <p className="text-sm text-gray-500">
                    {loading ? 'Fetching...' : portfolioData ? `${sortedData.length} Stocks Found` : 'No data'}
                </p>
              </div>

              <div className="relative w-full md:w-64">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-500" />
                </div>
                <input 
                  type="text" 
                  className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-2.5" 
                  placeholder="Search portfolio..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="overflow-x-auto min-h-[400px]">
              {loading ? (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                      <Loader2 className="animate-spin text-indigo-600" size={32} />
                      <p>Loading real-time portfolio data...</p>
                  </div>
              ) : portfolioData && portfolioData.length > 0 ? (
                  <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                      <tr>
                        <th scope="col" className="px-4 py-3 sticky left-0 bg-gray-50 z-10 border-r border-gray-200 w-[20%] min-w-[200px]">
                            Invested In
                        </th>
                        <th scope="col" className="px-4 py-3 text-right w-[20%]">Sector</th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%] min-w-[80px]"
                            onClick={() => handleSort('percentage')}
                        >
                            <div className="flex items-center justify-end">% Assets <SortIcon field="percentage"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%] min-w-[80px]"
                            onClick={() => handleSort('quantity')}
                        >
                            <div className="flex items-center justify-end">Quantity <SortIcon field="quantity"/></div>
                        </th>

                        {/* Dynamic History Columns - Up to 6 */}
                        {monthHeaders.length > 0 ? (
                            monthHeaders.slice(0, 6).map((header, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-400 font-medium">
                                    {header.split(' ')[0]} <br/> 
                                    <span className="text-[10px] opacity-75">{header.split(' ').slice(1).join(' ')}</span>
                                </th>
                            ))
                        ) : (
                            // Placeholder columns while loading first batch
                            [...Array(6)].map((_, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-300">
                                    M-{i}
                                </th>
                            ))
                        )}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {paginatedData.map((row, idx) => {
                          // Get cached history
                          const history = row.stockPk ? historyCache[row.stockPk] : undefined;
                          const isLoadingHistory = row.stockPk ? loadingHistoryMap[row.stockPk] : false;

                          return (
                          <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors">
                            <td className="px-4 py-3 font-medium text-gray-900 sticky left-0 bg-white group-hover:bg-gray-50 border-r border-gray-200 z-10 align-top">
                              <div className="flex flex-col gap-1">
                                  <div className="flex items-start gap-2">
                                    <button 
                                        onClick={() => onSelectStock(row.stockSymbol, row.stockName)}
                                        className="text-indigo-600 hover:text-indigo-800 hover:underline text-left text-sm w-full group/link flex items-center gap-2"
                                    >
                                        <span className="font-semibold break-words line-clamp-2 leading-tight">{row.stockName}</span>
                                        {row.stockUrl && (
                                            <a 
                                                href={row.stockUrl} 
                                                target="_blank" 
                                                rel="noreferrer" 
                                                className="text-gray-400 hover:text-indigo-500 opacity-0 group-hover/link:opacity-100 transition-opacity"
                                                title="View External"
                                                onClick={(e) => e.stopPropagation()}
                                            >
                                                <ExternalLink size={14} />
                                            </a>
                                        )}
                                    </button>
                                  </div>
                                  <div className="flex items-center gap-1 pl-0 mt-1">
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.dColor)}`} title={`Durability: ${row.d}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.vColor)}`} title={`Valuation: ${row.v}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.mColor)}`} title={`Momentum: ${row.m}`}></div>
                                  </div>
                              </div>
                            </td>
                            <td className="px-4 py-3 text-right text-xs align-top">
                                {row.sector}
                            </td>
                            <td className="px-4 py-3 text-right font-mono font-medium text-gray-900 text-sm align-top">
                                {row.percentage.toFixed(2)}%
                            </td>
                            <td className="px-4 py-3 text-right font-mono text-gray-600 text-sm align-top">
                                {(row.quantity / 1000).toLocaleString()} K
                            </td>

                            {/* History Cells */}
                            {[...Array(6)].map((_, hIdx) => {
                                const historyItem = history ? history[hIdx] : null;
                                return (
                                    <td key={hIdx} className="px-4 py-3 text-right font-mono text-sm align-top">
                                        {isLoadingHistory && hIdx === 0 ? (
                                            <div className="flex justify-end"><Loader2 className="animate-spin text-gray-300" size={12}/></div>
                                        ) : historyItem ? (
                                            <span className={getChangeColor(historyItem.change)}>
                                                {historyItem.change}
                                            </span>
                                        ) : (
                                            <span className="text-gray-300">-</span>
                                        )}
                                    </td>
                                );
                            })}
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
              ) : (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                      <p>{selectedFund.url ? "No portfolio data found." : "Please select a fund from the Dashboard to view its live portfolio."}</p>
                  </div>
              )}
            </div>

            {/* Pagination Controls */}
            {portfolioData && sortedData.length > 0 && (
              <div className="p-4 bg-gray-50 border-t border-gray-200 flex flex-col sm:flex-row items-center justify-between gap-4">
                <div className="text-xs text-gray-500">
                  Showing {paginatedData.length} of {sortedData.length} holdings
                  {selectedFund.url && " • Data Source: Trendlyne"}
                </div>

                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronLeft size={16} />
                  </button>

                  <span className="text-sm font-medium text-gray-700 px-2">
                    Page {currentPage} of {totalPages}
                  </span>

                  <button
                    onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                    disabled={currentPage === totalPages}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronRight size={16} />
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FundView;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, Upload, Loader2, ExternalLink, History, ChevronLeft, ChevronRight, PieChart as PieIcon, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { FundSnapshot, FundSearchResult, FundPortfolioHolding, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { parseExcelFile, fetchFundPortfolio, fetchFundHoldingHistory } from '../services/dataService';
import FundSearch from './FundSearch';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FundViewProps {
  funds: FundSnapshot[]; // For uploaded files
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: FundSearchResult | null;
}

type SortField = 'percentage' | 'quantity' | 'changeQuantity' | 'changePercentage';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;
const CHART_COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4', '#3b82f6', '#64748b'];

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(initialSelectedFund || null);

  // Data States
  const [portfolioData, setPortfolioData] = useState<FundPortfolioHolding[] | null>(null);
  const [fundMeta, setFundMeta] = useState<FundMeta | null>(null);
  const [sectorData, setSectorData] = useState<SectorDistribution[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // History Data State
  const [historyCache, setHistoryCache] = useState<Record<string | number, { date: string, change: string }[]>>({});
  const [monthHeaders, setMonthHeaders] = useState<string[]>([]);
  const [loadingHistoryMap, setLoadingHistoryMap] = useState<Record<string | number, boolean>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('percentage');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // File Upload State
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync prop changes
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFund(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // Fetch API Data whenever selectedFund changes and has URL
  useEffect(() => {
    const loadData = async () => {
      if (!selectedFund || !selectedFund.url) {
          setPortfolioData(null);
          setFundMeta(null);
          setSectorData([]);
          setHistoryCache({});
          setMonthHeaders([]);
          return;
      }

      setLoading(true);
      try {
        const data = await fetchFundPortfolio(selectedFund.url);
        if (data) {
            setPortfolioData(data.holdings);
            setFundMeta(data.meta);
            setSectorData(data.sectorDistribution);
        } else {
            setPortfolioData([]);
            setFundMeta(null);
            setSectorData([]);
        }
      } catch (err) {
          console.error("Failed to load fund portfolio", err);
          setPortfolioData([]);
      } finally {
          setLoading(false);
      }
    };

    loadData();
  }, [selectedFund]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          // Switch to offline view logic (not fully implemented in this iteration, keeping focus on API)
          setSelectedFund({ name: data.fundName, url: '' });
          alert("Offline file viewing is limited in this demo mode. Please use the API flow.");
        }
      } catch (err) {
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  };

  const sortedData = useMemo(() => {
      if (!portfolioData) return [];

      let data = [...portfolioData];
      if (searchTerm) {
          const lower = searchTerm.toLowerCase();
          data = data.filter(item => 
              item.stockName.toLowerCase().includes(lower) || 
              item.stockSymbol.toLowerCase().includes(lower) ||
              item.sector.toLowerCase().includes(lower)
          );
      }

      return data.sort((a, b) => {
          const valA = a[sortField];
          const valB = b[sortField];
          if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
          if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
          return 0;
      });
  }, [portfolioData, searchTerm, sortField, sortDirection]);

  // Pagination Logic
  const totalPages = Math.ceil(sortedData.length / ITEMS_PER_PAGE);
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
    // Note: We don't clear historyCache here to preserve loaded data if user navigates back
  }, [searchTerm, sortField, sortDirection, selectedFund]);

  // --- Fetch History for Visible Rows ---
  useEffect(() => {
      if (!fundMeta?.fundPk || !paginatedData.length) return;

      const fetchVisibleHistory = async () => {
          // Identify items that need fetching (have stockPk but no cache)
          const itemsToFetch = paginatedData.filter(item => 
              item.stockPk && !historyCache[item.stockPk] && !loadingHistoryMap[item.stockPk]
          );

          if (itemsToFetch.length === 0) return;

          // Mark as loading
          setLoadingHistoryMap(prev => {
              const next = { ...prev };
              itemsToFetch.forEach(i => { if(i.stockPk) next[i.stockPk] = true; });
              return next;
          });

          // Fetch in batches to avoid overwhelming the browser/proxy
          const BATCH_SIZE = 5;
          for (let i = 0; i < itemsToFetch.length; i += BATCH_SIZE) {
              const batch = itemsToFetch.slice(i, i + BATCH_SIZE);

              await Promise.all(batch.map(async (item) => {
                  if (!item.stockPk) return;
                  try {
                      const history = await fetchFundHoldingHistory(fundMeta.fundPk!, item.stockPk);
                      if (history && history.length > 0) {
                          // Extract only necessary data: last 6 months
                          const processed = history.slice(0, 6).map(h => ({
                              date: h["Holding Date"],
                              change: h["1M Change %"]
                          }));

                          setHistoryCache(prev => ({
                              ...prev,
                              [item.stockPk!]: processed
                          }));

                          // Update headers if this is the first successful fetch or has newer data
                          // We use functional update to access latest headers state if needed, 
                          // but since headers are mostly static for a fund month, simple set is fine.
                          setMonthHeaders(prevHeaders => {
                              if (prevHeaders.length === 0 && processed.length > 0) {
                                  return processed.map(p => p.date);
                              }
                              return prevHeaders;
                          });
                      }
                  } catch (e) {
                      console.error(`Failed history fetch for ${item.stockSymbol}`, e);
                  } finally {
                      setLoadingHistoryMap(prev => {
                          const next = { ...prev };
                          if (item.stockPk) delete next[item.stockPk];
                          return next;
                      });
                  }
              }));
          }
      };

      fetchVisibleHistory();
  }, [paginatedData, fundMeta, historyCache, loadingHistoryMap]);


  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <div className="ml-1 text-indigo-600">▲</div>
      : <div className="ml-1 text-indigo-600">▼</div>;
  };

  const getDotColor = (val: string) => {
      if (val === 'positive') return 'bg-green-500';
      if (val === 'negative') return 'bg-red-500';
      return 'bg-yellow-400';
  };

  // Helper to ensure URL is absolute for the user link
  const getDisplayUrl = (url: string) => {
      if (!url) return '';
      if (url.startsWith('http')) return url;
      return `https://trendlyne.com${url}`;
  };

  const renderLegendText = (value: string, entry: any) => {
    const { color } = entry;
    return (
        <span className="text-gray-600 font-medium ml-1 text-xs">
            {value} <span className="text-gray-400 font-normal">({entry.payload.value}%)</span>
        </span>
    );
  };

  // Helper to get change color
  const getChangeColor = (val: string | undefined) => {
      if (!val) return 'text-gray-300';
      if (val.includes('-')) return 'text-red-500';
      return 'text-green-500';
  };

  return (
    <div className="space-y-6">
      {/* Header Area */}
      <div className="flex items-center justify-between pb-4 border-b border-gray-100">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
        </div>

        {/* Upload Excel Button - Hidden until implemented */}
        <div className="flex items-center gap-4" style={{ display: 'none' }}>
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isUploading}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
          >
            {isUploading ? <Loader2 size={16} className="animate-spin"/> : <Upload size={16} />}
            Upload Excel
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept=".xlsx,.xls,.csv"
            onChange={handleFileChange}
          />
        </div>
      </div>

      {!selectedFund ? (
        <FundSearch onSelectFund={(fund) => setSelectedFund(fund)} />
      ) : (
        <div className="animate-fade-in space-y-6">
          <button 
            onClick={() => { setSelectedFund(null); setPortfolioData(null); setFundMeta(null); setSectorData([]); setHistoryCache({}); setMonthHeaders([]); }}
            className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
          >
            <ArrowLeft size={16} />
            Search different fund
          </button>

          {/* Top Section: Fund Info & Pie Chart */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             {/* Fund Description Card */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col justify-between">
                <div>
                    <div className="flex items-start justify-between mb-4">
                    <div>
                        <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            {selectedFund.name}
                            {selectedFund.url && (
                                <a 
                                    href={getDisplayUrl(selectedFund.url)} 
                                    target="_blank" 
                                    rel="noreferrer"
                                    className="text-gray-400 hover:text-indigo-600 transition-colors"
                                    title="View full report on Trendlyne"
                                >
                                    <ExternalLink size={20} />
                                </a>
                            )}
                        </h3>
                        {loading ? (
                        <div className="h-6 w-32 bg-gray-100 animate-pulse rounded mt-2"></div>
                        ) : fundMeta?.category && (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 mt-2">
                            {fundMeta.category}
                        </span>
                        )}
                    </div>
                    </div>

                    <div className="prose prose-sm text-gray-500 max-w-none">
                    {loading ? (
                        <div className="space-y-2">
                        <div className="h-4 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-5/6 animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-4/6 animate-pulse"></div>
                        </div>
                    ) : (
                        <p>{fundMeta?.description || "No description available for this fund category."}</p>
                    )}
                    </div>
                </div>
             </div>

             {/* Sector Pie Chart */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col">
                <h4 className="font-semibold text-gray-800 mb-2 flex items-center gap-2 text-sm">
                   <PieIcon size={16} className="text-indigo-500"/>
                   Sector Allocation
                </h4>
                <div className="flex-1 min-h-[220px] relative">
                   {loading ? (
                      <div className="absolute inset-0 flex items-center justify-center">
                         <Loader2 className="animate-spin text-indigo-400" />
                      </div>
                   ) : sectorData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                         <PieChart>
                            <Pie
                               data={sectorData}
                               dataKey="value"
                               nameKey="name"
                               cx="50%"
                               cy="50%"
                               innerRadius={50}
                               outerRadius={80}
                               paddingAngle={2}
                            >
                               {sectorData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={CHART_COLORS[index % CHART_COLORS.length]} />
                               ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `${value}%`} />
                            <Legend 
                                layout="horizontal" 
                                verticalAlign="bottom" 
                                align="center" 
                                iconSize={8} 
                                wrapperStyle={{ fontSize: '10px', paddingTop: '10px' }}
                                formatter={renderLegendText}
                            />
                         </PieChart>
                      </ResponsiveContainer>
                   ) : (
                      <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                         No sector data available
                      </div>
                   )}
                </div>
             </div>
          </div>

          {/* Holdings Table Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
            <div className="p-6 border-b border-gray-200 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
              <div>
                <h3 className="text-lg font-bold text-gray-900">Portfolio Holdings</h3>
                <p className="text-sm text-gray-500">
                    {loading ? 'Fetching...' : portfolioData ? `${sortedData.length} Stocks Found` : 'No data'}
                </p>
              </div>

              <div className="relative w-full md:w-64">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-500" />
                </div>
                <input 
                  type="text" 
                  className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-2.5" 
                  placeholder="Search portfolio..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="overflow-x-auto min-h-[400px]">
              {loading ? (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                      <Loader2 className="animate-spin text-indigo-600" size={32} />
                      <p>Loading real-time portfolio data...</p>
                  </div>
              ) : portfolioData && portfolioData.length > 0 ? (
                  <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                      <tr>
                        <th scope="col" className="px-4 py-3 sticky left-0 bg-gray-50 z-10 border-r border-gray-200 w-[20%] min-w-[200px]">
                            Invested In
                        </th>
                        <th scope="col" className="px-4 py-3 text-right w-[20%]">Sector</th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%] min-w-[80px]"
                            onClick={() => handleSort('percentage')}
                        >
                            <div className="flex items-center justify-end">% Assets <SortIcon field="percentage"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%] min-w-[80px]"
                            onClick={() => handleSort('quantity')}
                        >
                            <div className="flex items-center justify-end">Quantity <SortIcon field="quantity"/></div>
                        </th>

                        {/* Dynamic History Columns - Up to 6 */}
                        {monthHeaders.length > 0 ? (
                            monthHeaders.slice(0, 6).map((header, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-400 font-medium">
                                    {header.split(' ')[0]} <br/> 
                                    <span className="text-[10px] opacity-75">{header.split(' ').slice(1).join(' ')}</span>
                                </th>
                            ))
                        ) : (
                            // Placeholder columns while loading first batch
                            [...Array(6)].map((_, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-300">
                                    M-{i}
                                </th>
                            ))
                        )}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {paginatedData.map((row, idx) => {
                          // Get cached history
                          const history = row.stockPk ? historyCache[row.stockPk] : undefined;
                          const isLoadingHistory = row.stockPk ? loadingHistoryMap[row.stockPk] : false;

                          return (
                          <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors">
                            <td className="px-4 py-3 font-medium text-gray-900 sticky left-0 bg-white group-hover:bg-gray-50 border-r border-gray-200 z-10 align-top">
                              <div className="flex flex-col gap-1">
                                  <div className="flex items-start gap-2">
                                    <div className="mt-0.5 text-gray-400">
                                        <History size={14} />
                                    </div>
                                    <button 
                                        onClick={() => onSelectStock(row.stockSymbol, row.stockName)}
                                        className="text-indigo-600 hover:text-indigo-800 hover:underline text-left text-sm w-full group/link flex items-center gap-2"
                                    >
                                        <span className="font-semibold break-words line-clamp-2 leading-tight">{row.stockName}</span>
                                        {row.stockUrl && (
                                            <a 
                                                href={row.stockUrl} 
                                                target="_blank" 
                                                rel="noreferrer" 
                                                className="text-gray-400 hover:text-indigo-500 opacity-0 group-hover/link:opacity-100 transition-opacity"
                                                title="View External"
                                                onClick={(e) => e.stopPropagation()}
                                            >
                                                <ExternalLink size={14} />
                                            </a>
                                        )}
                                    </button>
                                  </div>
                                  <div className="flex items-center gap-1 pl-6 mt-1">
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.dColor)}`} title={`Durability: ${row.d}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.vColor)}`} title={`Valuation: ${row.v}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.mColor)}`} title={`Momentum: ${row.m}`}></div>
                                  </div>
                              </div>
                            </td>
                            <td className="px-4 py-3 text-right text-xs align-top">
                                {row.sector}
                            </td>
                            <td className="px-4 py-3 text-right font-mono font-medium text-gray-900 text-sm align-top">
                                {row.percentage.toFixed(2)}%
                            </td>
                            <td className="px-4 py-3 text-right font-mono text-gray-600 text-sm align-top">
                                {(row.quantity / 1000).toLocaleString()} K
                            </td>

                            {/* History Cells */}
                            {[...Array(6)].map((_, hIdx) => {
                                const historyItem = history ? history[hIdx] : null;
                                return (
                                    <td key={hIdx} className="px-4 py-3 text-right font-mono text-sm align-top">
                                        {isLoadingHistory && hIdx === 0 ? (
                                            <div className="flex justify-end"><Loader2 className="animate-spin text-gray-300" size={12}/></div>
                                        ) : historyItem ? (
                                            <span className={getChangeColor(historyItem.change)}>
                                                {historyItem.change}
                                            </span>
                                        ) : (
                                            <span className="text-gray-300">-</span>
                                        )}
                                    </td>
                                );
                            })}
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
              ) : (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                      <p>{selectedFund.url ? "No portfolio data found." : "Please select a fund from the Dashboard to view its live portfolio."}</p>
                  </div>
              )}
            </div>

            {/* Pagination Controls */}
            {portfolioData && sortedData.length > 0 && (
              <div className="p-4 bg-gray-50 border-t border-gray-200 flex flex-col sm:flex-row items-center justify-between gap-4">
                <div className="text-xs text-gray-500">
                  Showing {paginatedData.length} of {sortedData.length} holdings
                  {selectedFund.url && " • Data Source: Trendlyne"}
                </div>

                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronLeft size={16} />
                  </button>

                  <span className="text-sm font-medium text-gray-700 px-2">
                    Page {currentPage} of {totalPages}
                  </span>

                  <button
                    onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                    disabled={currentPage === totalPages}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronRight size={16} />
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FundView;

import React, { useEffect, useState, useMemo } from 'react';
import { ArrowLeft, ExternalLink, TrendingUp, TrendingDown, Layers, Loader2, Search, Filter, ArrowUp, ArrowDown, ChevronLeft, ChevronRight, BarChart2, RefreshCw } from 'lucide-react';
import { StockPriceData, StockMFAnalysis, MutualFundHolding, FundSearchResult } from '../types';
import { fetchLiveStockPrice, fetchMutualFundHoldingsForStock } from '../services/dataService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface StockDashboardProps {
  symbol: string;
  stockName: string;
  onBack: () => void;
  onSelectFund: (fund: FundSearchResult) => void;
}

type SortField = 'sharesHeld' | 'aum' | 'changePercent' | 'change' | 'aumPercent';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;

const StockDashboard: React.FC<StockDashboardProps> = ({ symbol, stockName, onBack, onSelectFund }) => {
  const [priceData, setPriceData] = useState<StockPriceData | null>(null);
  const [loadingPrice, setLoadingPrice] = useState(false);

  const [mfData, setMfData] = useState<StockMFAnalysis | null>(null);
  const [loadingMF, setLoadingMF] = useState(false);

  const [filterQuery, setFilterQuery] = useState('');

  // Sorting State
  const [sortField, setSortField] = useState<SortField>('sharesHeld');
  const [sortMonth, setSortMonth] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // Fetch Data on Mount
  useEffect(() => {
    const loadData = async () => {

      // 1. Fetch Live Price (via new API)
      setLoadingPrice(true);
      fetchLiveStockPrice(symbol).then(data => {
        setPriceData(data);
        setLoadingPrice(false);
      });

       // 2. Fetch MF Holdings (Trendlyne API chain)
      setLoadingMF(true);
      fetchMutualFundHoldingsForStock(symbol).then(data => {
        setMfData(data);
        setLoadingMF(false);
      });


    };
    loadData();
  }, [symbol, stockName]);

  const handleRefreshPrice = async () => {
    setLoadingPrice(true);
    const data = await fetchLiveStockPrice(symbol);
    setPriceData(data);
    setLoadingPrice(false);
  };

  // Determine available months from data
  const monthColumns = useMemo(() => {
    if (!mfData || mfData.holdings.length === 0) return [];
    const allMonths = Array.from(new Set(mfData.holdings.flatMap(h => h.history.map(hist => hist.month))));
    // Sort descending by date
    const sortedMonths = allMonths.sort((a, b) => new Date(b).getTime() - new Date(a).getTime()).slice(0, 3);

    // Set default sort month if not set
    if (!sortMonth && sortedMonths.length > 0) {
      setSortMonth(sortedMonths[0]);
    }

    return sortedMonths;
  }, [mfData, sortMonth]);

  // Filter and Sort Logic
  const filteredSortedHoldings = useMemo(() => {
    if (!mfData) return [];

    let result = mfData.holdings.filter(h => 
      h.fundName.toLowerCase().includes(filterQuery.toLowerCase())
    );

    const targetMonth = sortMonth || monthColumns[0];

    result.sort((a, b) => {
      const dataA = a.history.find(h => h.month === targetMonth);
      const dataB = b.history.find(h => h.month === targetMonth);

      // Handle missing data for specific months (treat as 0 or min value)
      const valA = dataA ? (dataA[sortField] || 0) : -Infinity;
      const valB = dataB ? (dataB[sortField] || 0) : -Infinity;

      if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
      if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [mfData, filterQuery, sortField, sortDirection, sortMonth, monthColumns]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredSortedHoldings.length / ITEMS_PER_PAGE);
  const paginatedHoldings = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredSortedHoldings.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredSortedHoldings, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
  }, [filterQuery, sortField, sortDirection, sortMonth]);

  const handleSort = (field: SortField, month: string) => {
    if (sortField === field && sortMonth === month) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortMonth(month);
      setSortDirection('desc');
    }
  };

  const SortIcon = ({ field, month }: { field: SortField, month: string }) => {
    const isActive = sortField === field && sortMonth === month;
    if (!isActive) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <ArrowUp size={12} className="ml-1 text-indigo-600" />
      : <ArrowDown size={12} className="ml-1 text-indigo-600" />;
  };

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="flex justify-between items-center">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
        >
          <ArrowLeft size={16} />
          Back to Search
        </button>
      </div>

      {/* Top Section: Price & Graph */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Price Card */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start mb-4">
              <div>
                <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-3">
                  {stockName}
                  {mfData?.sourceUrl && (
                    <a 
                      href={mfData.sourceUrl} 
                      target="_blank" 
                      rel="noreferrer"
                      className="text-gray-400 hover:text-indigo-600 transition-colors"
                      title="View full report on Trendlyne"
                    >
                      <ExternalLink size={20} />
                    </a>
                  )}
                </h1>
                <div className="flex items-center gap-2 text-gray-500 text-sm mt-1 flex-wrap">
                  <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs">{symbol}</span>
                  <span>•</span>
                  <span>NSE/BSE</span>
                  {mfData && (
                    <>
                      <span>•</span>
                      <span className="font-medium text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded text-xs">
                         MF Count: {mfData.holdings.length}
                      </span>
                    </>
                  )}
                </div>
              </div>
              {priceData ? (
                <div className="text-right">
                    <div className="flex items-center justify-end gap-3 mb-1">
                        <div className="text-2xl font-bold text-gray-900">₹{priceData.current_price}</div>
                        <button 
                            onClick={handleRefreshPrice} 
                            disabled={loadingPrice}
                            className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400 hover:text-indigo-600 transition-colors"
                            title="Refresh Price"
                        >
                            <RefreshCw size={14} className={loadingPrice ? "animate-spin" : ""} />
                        </button>
                    </div>

                    <div className="flex items-center justify-end gap-2 text-sm">
                        <span className="text-gray-500 font-medium text-xs bg-gray-50 px-1.5 py-0.5 rounded" title="Volume">
                           V: {priceData.volume}
                        </span>
                        <span className={`flex items-center font-medium ${
                           priceData.todays_change_direction === 'up' ? 'text-green-600' : 
                           priceData.todays_change_direction === 'down' ? 'text-red-600' : 'text-gray-500'
                        }`}>
                            {priceData.todays_change_direction === 'up' ? <TrendingUp size={14} className="mr-1" /> : 
                             priceData.todays_change_direction === 'down' ? <TrendingDown size={14} className="mr-1" /> : null}
                            {priceData.todays_change_number} ({priceData.todays_change_percentage})
                        </span>
                    </div>
                    <div className="text-[10px] text-gray-400 mt-1">
                       Updated: {priceData.last_updated}
                    </div>
                </div>
              ) : loadingPrice ? (
                 <div className="text-right">
                    <div className="h-8 w-24 bg-gray-100 animate-pulse rounded mb-1 ml-auto"></div>
                    <div className="h-4 w-16 bg-gray-100 animate-pulse rounded ml-auto"></div>
                 </div>
              ) : null}
            </div>

            {loadingPrice && !priceData && (
              <div className="flex items-center gap-2 text-indigo-600 text-sm mt-2">
                <Loader2 className="animate-spin" size={16} /> Fetching live price...
              </div>
            )}

          </div>

          <div className="mt-6 pt-6 border-t border-gray-100">
             <div className="text-sm text-gray-500 mb-1">Stock Analysis</div>
             <p className="text-xs text-gray-400">
               Real-time data fetched from market sources via Gemini. MF data aggregated from monthly disclosures.
             </p>
          </div>
        </div>

        {/* Graph Card */}
        <div className="lg:col-span-2 bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-semibold text-gray-900 flex items-center gap-2">
               <BarChart2 size={20} className="text-indigo-600" />
               Institutional Interest
            </h3>
            <span className="text-xs text-gray-400 bg-gray-50 px-2 py-1 rounded">Total Shares Held (Aggregated)</span>
          </div>

          <div className="h-64">
            {loadingMF ? (
               <div className="h-full flex items-center justify-center text-gray-400 gap-2">
                 <Loader2 className="animate-spin" /> Loading Chart...
               </div>
            ) : mfData && mfData.aggregateHistory.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={mfData.aggregateHistory}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                    <XAxis dataKey="month" stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} />
                    <YAxis 
                      stroke="#9ca3af" 
                      fontSize={12} 
                      tickLine={false} 
                      axisLine={false} 
                      tickFormatter={(val) => (val / 1000000).toFixed(1) + 'M'}
                    />
                    <Tooltip 
                      cursor={{fill: '#f3f4f6'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      formatter={(value: number) => [value.toLocaleString(), 'Shares Held']}
                    />
                    <Bar dataKey="totalShares" radius={[4, 4, 0, 0]}>
                      {mfData.aggregateHistory.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={index === mfData.aggregateHistory.length - 1 ? '#4f46e5' : '#c7d2fe'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
            ) : (
                <div className="h-full flex items-center justify-center text-gray-400">
                   No historical data available.
                </div>
            )}
          </div>
        </div>
      </div>

      {/* Holdings Table Section */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden flex flex-col">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
           <h3 className="font-semibold text-gray-900 flex items-center gap-2">
              <Layers size={18} className="text-indigo-600" />
              Mutual Fund Portfolios
           </h3>

           <div className="relative w-full md:w-72">
              <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                <Search className="w-4 h-4 text-gray-400" />
              </div>
              <input 
                type="text" 
                className="bg-white border border-gray-200 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-2.5 shadow-sm" 
                placeholder="Filter funds..." 
                value={filterQuery}
                onChange={(e) => setFilterQuery(e.target.value)}
              />
           </div>
        </div>

        <div className="overflow-x-auto">
          {loadingMF ? (
            <div className="p-12 flex flex-col items-center justify-center text-gray-400 gap-3">
               <Loader2 className="animate-spin text-indigo-500" size={32} />
               <p>Fetching detailed holdings...</p>
            </div>
          ) : (
            <table className="w-full text-sm text-left text-gray-500 border-collapse">
              <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                {/* Header Row 1: Grouped Month Names */}
                <tr>
                  <th rowSpan={2} className="px-6 py-4 font-semibold border-r border-gray-200 bg-gray-50 sticky left-0 z-10 w-64 min-w-[250px]">
                    MF
                  </th>
                  {monthColumns.map((month, index) => (
                    <th 
                      key={month} 
                      colSpan={index === 0 ? 4 : 2} // Latest month gets 4 columns (removed AUM Cr), others get 2
                      className={`px-4 py-2 text-center border-r border-gray-200 ${index === 0 ? 'bg-indigo-50 text-indigo-900 font-bold' : ''}`}
                    >
                      {month}
                    </th>
                  ))}
                </tr>
                {/* Header Row 2: Columns */}
                <tr>
                  {monthColumns.map((month, index) => (
                     <React.Fragment key={`${month}-subheaders`}>
                       {index === 0 ? (
                         // Full columns for latest month (Removed AUM Cr)
                         <>
                           <th 
                             className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                             onClick={() => handleSort('aumPercent', month)}
                           >
                             <div className="flex items-center justify-end">AUM % <SortIcon field="aumPercent" month={month}/></div>
                           </th>
                           <th 
                             className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                             onClick={() => handleSort('sharesHeld', month)}
                           >
                             <div className="flex items-center justify-end">Shares Held <SortIcon field="sharesHeld" month={month}/></div>
                           </th>
                           <th 
                             className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                             onClick={() => handleSort('change', month)}
                           >
                             <div className="flex items-center justify-end">Month Change <SortIcon field="change" month={month}/></div>
                           </th>
                           <th 
                             className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-200"
                             onClick={() => handleSort('changePercent', month)}
                           >
                             <div className="flex items-center justify-end">Change % <SortIcon field="changePercent" month={month}/></div>
                           </th>
                         </>
                       ) : (
                         // Reduced columns for other months
                         <>
                           <th 
                            className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-100"
                            onClick={() => handleSort('sharesHeld', month)}
                           >
                             <div className="flex items-center justify-end">Shares Held <SortIcon field="sharesHeld" month={month}/></div>
                           </th>
                           <th 
                            className="px-4 py-2 text-right cursor-pointer hover:bg-gray-100 group border-r border-gray-200"
                            onClick={() => handleSort('changePercent', month)}
                           >
                             <div className="flex items-center justify-end">Change % <SortIcon field="changePercent" month={month}/></div>
                           </th>
                         </>
                       )}
                     </React.Fragment>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {paginatedHoldings.length > 0 ? paginatedHoldings.map((holding, idx) => (
                  <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4 border-r border-gray-100 sticky left-0 bg-white group-hover:bg-gray-50 z-10">
                      <div className="flex items-center gap-2 group/link">
                        <button 
                          onClick={() => onSelectFund({ name: holding.fundName, url: holding.fundUrl })}
                          className="font-medium text-indigo-600 hover:text-indigo-800 text-left transition-colors line-clamp-2"
                        >
                          {holding.fundName}
                        </button>
                        {holding.fundUrl && (
                           <a 
                             href={holding.fundUrl} 
                             target="_blank" 
                             rel="noreferrer"
                             className="text-gray-300 hover:text-indigo-500 transition-colors opacity-0 group-hover/link:opacity-100"
                             title="View on Trendlyne"
                           >
                             <ExternalLink size={14} />
                           </a>
                        )}
                      </div>
                    </td>

                    {monthColumns.map((month, mIndex) => {
                      const data = holding.history.find(h => h.month === month);
                      const isLatest = mIndex === 0;

                      if (!data) {
                        return (
                          <React.Fragment key={`${month}-empty`}>
                             {isLatest ? (
                               <>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-200">-</td>
                               </>
                             ) : (
                               <>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-100">-</td>
                                 <td className="px-4 py-4 text-right text-gray-300 border-r border-gray-200">-</td>
                               </>
                             )}
                          </React.Fragment>
                        );
                      }

                      return (
                        <React.Fragment key={`${month}-data`}>
                          {isLatest ? (
                             <>
                               {/* AUM % */}
                               <td className="px-4 py-4 text-right font-mono text-gray-700 border-r border-gray-100 bg-indigo-50/20">
                                 {data.aumPercent ? `${data.aumPercent.toFixed(2)}%` : '-'}
                               </td>
                               {/* Shares Held */}
                               <td className="px-4 py-4 text-right font-mono text-gray-900 font-medium border-r border-gray-100 bg-indigo-50/30">
                                 {data.sharesHeld.toLocaleString()}
                               </td>
                               {/* Month Change (Absolute) */}
                               <td className="px-4 py-4 text-right font-mono border-r border-gray-100 bg-indigo-50/20">
                                  {data.change ? (
                                     <span className={data.change > 0 ? 'text-green-600' : data.change < 0 ? 'text-red-600' : 'text-gray-400'}>
                                       {data.change.toLocaleString()}
                                     </span>
                                  ) : <span className="text-gray-300">0</span>}
                               </td>
                               {/* Month Change % */}
                               <td className="px-4 py-4 text-right font-mono border-r border-gray-200 bg-indigo-50/20">
                                 <div className={`flex items-center justify-end gap-1 ${
                                   data.changePercent > 0 ? 'text-green-600 font-medium' : 
                                   data.changePercent < 0 ? 'text-red-600 font-medium' : 'text-gray-400'
                                 }`}>
                                    {data.changePercent > 0 ? `+${data.changePercent}%` : `${data.changePercent}%`}
                                 </div>
                               </td>
                             </>
                          ) : (
                             <>
                               {/* Previous Month Shares */}
                               <td className="px-4 py-4 text-right font-mono text-gray-600 border-r border-gray-100">
                                 {data.sharesHeld.toLocaleString()}
                               </td>
                               {/* Previous Month Change % */}
                               <td className="px-4 py-4 text-right font-mono border-r border-gray-200">
                                 <span className={data.changePercent > 0 ? 'text-green-600' : data.changePercent < 0 ? 'text-red-600' : 'text-gray-400'}>
                                   {data.changePercent}%
                                 </span>
                               </td>
                             </>
                          )}
                        </React.Fragment>
                      );
                    })}
                  </tr>
                )) : (
                   <tr>
                     <td colSpan={1 + (monthColumns.length * 2) + 2} className="px-6 py-12 text-center text-gray-400">
                       No funds found matching your search.
                     </td>
                   </tr>
                )}
              </tbody>
            </table>
          )}
        </div>

        {mfData && filteredSortedHoldings.length > 0 && (
          <div className="p-4 bg-gray-50 border-t border-gray-200 flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="text-xs text-gray-500">
              Showing {paginatedHoldings.length} of {filteredSortedHoldings.length} funds
              {mfData.sourceUrl && " • Data Source: Trendlyne"}
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                disabled={currentPage === 1}
                className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
              >
                <ChevronLeft size={16} />
              </button>

              <span className="text-sm font-medium text-gray-700 px-2">
                Page {currentPage} of {totalPages}
              </span>

              <button
                onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                disabled={currentPage === totalPages}
                className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default StockDashboard;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, Upload, Loader2, ExternalLink, History, ChevronLeft, ChevronRight, PieChart as PieIcon, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { FundSnapshot, FundSearchResult, FundPortfolioHolding, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { parseExcelFile, fetchFundPortfolio, fetchFundHoldingHistory } from '../services/dataService';
import FundSearch from './FundSearch';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FundViewProps {
  funds: FundSnapshot[]; // For uploaded files
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: FundSearchResult | null;
}

type SortField = 'percentage' | 'quantity' | 'changeQuantity' | 'changePercentage';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;
const CHART_COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4', '#3b82f6', '#64748b'];

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(initialSelectedFund || null);

  // Data States
  const [portfolioData, setPortfolioData] = useState<FundPortfolioHolding[] | null>(null);
  const [fundMeta, setFundMeta] = useState<FundMeta | null>(null);
  const [sectorData, setSectorData] = useState<SectorDistribution[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // History Data State
  const [historyCache, setHistoryCache] = useState<Record<string | number, { date: string, change: string }[]>>({});
  const [monthHeaders, setMonthHeaders] = useState<string[]>([]);
  const [loadingHistoryMap, setLoadingHistoryMap] = useState<Record<string | number, boolean>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('percentage');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // File Upload State
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync prop changes
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFund(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // Fetch API Data whenever selectedFund changes and has URL
  useEffect(() => {
    const loadData = async () => {
      if (!selectedFund || !selectedFund.url) {
          setPortfolioData(null);
          setFundMeta(null);
          setSectorData([]);
          setHistoryCache({});
          setMonthHeaders([]);
          return;
      }

      setLoading(true);
      try {
        const data = await fetchFundPortfolio(selectedFund.url);
        if (data) {
            setPortfolioData(data.holdings);
            setFundMeta(data.meta);
            setSectorData(data.sectorDistribution);
        } else {
            setPortfolioData([]);
            setFundMeta(null);
            setSectorData([]);
        }
      } catch (err) {
          console.error("Failed to load fund portfolio", err);
          setPortfolioData([]);
      } finally {
          setLoading(false);
      }
    };

    loadData();
  }, [selectedFund]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          // Switch to offline view logic (not fully implemented in this iteration, keeping focus on API)
          setSelectedFund({ name: data.fundName, url: '' });
          alert("Offline file viewing is limited in this demo mode. Please use the API flow.");
        }
      } catch (err) {
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  };

  const sortedData = useMemo(() => {
      if (!portfolioData) return [];

      let data = [...portfolioData];
      if (searchTerm) {
          const lower = searchTerm.toLowerCase();
          data = data.filter(item => 
              item.stockName.toLowerCase().includes(lower) || 
              item.stockSymbol.toLowerCase().includes(lower) ||
              item.sector.toLowerCase().includes(lower)
          );
      }

      return data.sort((a, b) => {
          const valA = a[sortField];
          const valB = b[sortField];
          if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
          if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
          return 0;
      });
  }, [portfolioData, searchTerm, sortField, sortDirection]);

  // Pagination Logic
  const totalPages = Math.ceil(sortedData.length / ITEMS_PER_PAGE);
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
    // Note: We don't clear historyCache here to preserve loaded data if user navigates back
  }, [searchTerm, sortField, sortDirection, selectedFund]);

  // --- Fetch History for Visible Rows ---
  useEffect(() => {
      if (!fundMeta?.fundPk || !paginatedData.length) return;

      const fetchVisibleHistory = async () => {
          // Identify items that need fetching (have stockPk but no cache)
          const itemsToFetch = paginatedData.filter(item => 
              item.stockPk && !historyCache[item.stockPk] && !loadingHistoryMap[item.stockPk]
          );

          if (itemsToFetch.length === 0) return;

          // Mark as loading
          setLoadingHistoryMap(prev => {
              const next = { ...prev };
              itemsToFetch.forEach(i => { if(i.stockPk) next[i.stockPk] = true; });
              return next;
          });

          // Fetch in batches to avoid overwhelming the browser/proxy
          const BATCH_SIZE = 5;
          for (let i = 0; i < itemsToFetch.length; i += BATCH_SIZE) {
              const batch = itemsToFetch.slice(i, i + BATCH_SIZE);

              await Promise.all(batch.map(async (item) => {
                  if (!item.stockPk) return;
                  try {
                      const history = await fetchFundHoldingHistory(fundMeta.fundPk!, item.stockPk);
                      if (history && history.length > 0) {
                          // Extract only necessary data: last 6 months
                          const processed = history.slice(0, 6).map(h => ({
                              date: h["Holding Date"],
                              change: h["1M Change %"]
                          }));

                          setHistoryCache(prev => ({
                              ...prev,
                              [item.stockPk!]: processed
                          }));

                          // Update headers if this is the first successful fetch or has newer data
                          setMonthHeaders(prevHeaders => {
                              if (prevHeaders.length === 0 && processed.length > 0) {
                                  return processed.map(p => p.date);
                              }
                              return prevHeaders;
                          });
                      }
                  } catch (e) {
                      console.error(`Failed history fetch for ${item.stockSymbol}`, e);
                  } finally {
                      setLoadingHistoryMap(prev => {
                          const next = { ...prev };
                          if (item.stockPk) delete next[item.stockPk];
                          return next;
                      });
                  }
              }));
          }
      };

      fetchVisibleHistory();
  }, [paginatedData, fundMeta, historyCache, loadingHistoryMap]);


  const SortIcon = ({ field }: { field: SortField }) => {
    if (sortField !== field) return <div className="w-3 h-3 ml-1 opacity-0 group-hover:opacity-30"></div>;
    return sortDirection === 'asc' 
      ? <div className="ml-1 text-indigo-600">▲</div>
      : <div className="ml-1 text-indigo-600">▼</div>;
  };

  const getDotColor = (val: string) => {
      if (val === 'positive') return 'bg-green-500';
      if (val === 'negative') return 'bg-red-500';
      return 'bg-yellow-400';
  };

  const getValueColor = (val: number) => {
    if (val > 0) return 'text-green-600';
    if (val < 0) return 'text-red-600';
    return 'text-gray-400';
  };

  // Helper to ensure URL is absolute for the user link
  const getDisplayUrl = (url: string) => {
      if (!url) return '';
      if (url.startsWith('http')) return url;
      return `https://trendlyne.com${url}`;
  };

  const renderLegendText = (value: string, entry: any) => {
    const { color } = entry;
    return (
        <span className="text-gray-600 font-medium ml-1 text-xs">
            {value} <span className="text-gray-400 font-normal">({entry.payload.value}%)</span>
        </span>
    );
  };

  // Helper to get change color for history
  const getHistoryChangeColor = (val: string | undefined) => {
      if (!val) return 'text-gray-300';
      if (val.includes('-')) return 'text-red-500';
      return 'text-green-500';
  };

  return (
    <div className="space-y-6">
      {/* Header Area */}
      <div className="flex items-center justify-between pb-4 border-b border-gray-100">
        <div>
           <h2 className="text-2xl font-bold text-gray-900">Fund Monitor</h2>
        </div>

        {/* Upload Excel Button - Hidden until implemented */}
        <div className="flex items-center gap-4" style={{ display: 'none' }}>
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={isUploading}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
          >
            {isUploading ? <Loader2 size={16} className="animate-spin"/> : <Upload size={16} />}
            Upload Excel
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept=".xlsx,.xls,.csv"
            onChange={handleFileChange}
          />
        </div>
      </div>

      {!selectedFund ? (
        <FundSearch onSelectFund={(fund) => setSelectedFund(fund)} />
      ) : (
        <div className="animate-fade-in space-y-6">
          <button 
            onClick={() => { setSelectedFund(null); setPortfolioData(null); setFundMeta(null); setSectorData([]); setHistoryCache({}); setMonthHeaders([]); }}
            className="flex items-center gap-2 text-sm text-gray-500 hover:text-indigo-600 transition-colors"
          >
            <ArrowLeft size={16} />
            Search different fund
          </button>

          {/* Top Section: Fund Info & Pie Chart */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             {/* Fund Description Card */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col justify-between">
                <div>
                    <div className="flex items-start justify-between mb-4">
                    <div>
                        <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            {selectedFund.name}
                            {selectedFund.url && (
                                <a 
                                    href={getDisplayUrl(selectedFund.url)} 
                                    target="_blank" 
                                    rel="noreferrer"
                                    className="text-gray-400 hover:text-indigo-600 transition-colors"
                                    title="View full report on Trendlyne"
                                >
                                    <ExternalLink size={20} />
                                </a>
                            )}
                        </h3>
                        {loading ? (
                        <div className="h-6 w-32 bg-gray-100 animate-pulse rounded mt-2"></div>
                        ) : fundMeta?.category && (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 mt-2">
                            {fundMeta.category}
                        </span>
                        )}
                    </div>
                    </div>

                    <div className="prose prose-sm text-gray-500 max-w-none">
                    {loading ? (
                        <div className="space-y-2">
                        <div className="h-4 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-5/6 animate-pulse"></div>
                        <div className="h-4 bg-gray-100 rounded w-4/6 animate-pulse"></div>
                        </div>
                    ) : (
                        <p>{fundMeta?.description || "No description available for this fund category."}</p>
                    )}
                    </div>
                </div>
             </div>

             {/* Sector Pie Chart */}
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col">
                <h4 className="font-semibold text-gray-800 mb-2 flex items-center gap-2 text-sm">
                   <PieIcon size={16} className="text-indigo-500"/>
                   Sector Allocation
                </h4>
                <div className="flex-1 min-h-[220px] relative">
                   {loading ? (
                      <div className="absolute inset-0 flex items-center justify-center">
                         <Loader2 className="animate-spin text-indigo-400" />
                      </div>
                   ) : sectorData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                         <PieChart>
                            <Pie
                               data={sectorData}
                               dataKey="value"
                               nameKey="name"
                               cx="50%"
                               cy="50%"
                               innerRadius={50}
                               outerRadius={80}
                               paddingAngle={2}
                            >
                               {sectorData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={CHART_COLORS[index % CHART_COLORS.length]} />
                               ))}
                            </Pie>
                            <Tooltip formatter={(value: number) => `${value}%`} />
                            <Legend 
                                layout="horizontal" 
                                verticalAlign="bottom" 
                                align="center" 
                                iconSize={8} 
                                wrapperStyle={{ fontSize: '10px', paddingTop: '10px' }}
                                formatter={renderLegendText}
                            />
                         </PieChart>
                      </ResponsiveContainer>
                   ) : (
                      <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                         No sector data available
                      </div>
                   )}
                </div>
             </div>
          </div>

          {/* Holdings Table Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
            <div className="p-6 border-b border-gray-200 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
              <div>
                <h3 className="text-lg font-bold text-gray-900">Portfolio Holdings</h3>
                <p className="text-sm text-gray-500">
                    {loading ? 'Fetching...' : portfolioData ? `${sortedData.length} Stocks Found` : 'No data'}
                </p>
              </div>

              <div className="relative w-full md:w-64">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                  <Search className="w-4 h-4 text-gray-500" />
                </div>
                <input 
                  type="text" 
                  className="bg-white border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 p-2.5" 
                  placeholder="Search portfolio..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="overflow-x-auto min-h-[400px]">
              {loading ? (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                      <Loader2 className="animate-spin text-indigo-600" size={32} />
                      <p>Loading real-time portfolio data...</p>
                  </div>
              ) : portfolioData && portfolioData.length > 0 ? (
                  <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 border-b border-gray-200">
                      <tr>
                        <th scope="col" className="px-4 py-3 sticky left-0 bg-gray-50 z-10 border-r border-gray-200 w-[20%] min-w-[200px]">
                            Invested In
                        </th>
                        <th scope="col" className="px-4 py-3 text-right w-[15%]">Sector</th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('percentage')}
                        >
                            <div className="flex items-center justify-end">% Assets <SortIcon field="percentage"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('quantity')}
                        >
                            <div className="flex items-center justify-end">Quantity <SortIcon field="quantity"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('changeQuantity')}
                        >
                            <div className="flex items-center justify-end">Chg Qty <SortIcon field="changeQuantity"/></div>
                        </th>
                        <th 
                            scope="col" 
                            className="px-4 py-3 text-right cursor-pointer hover:bg-gray-100 group w-[10%]"
                            onClick={() => handleSort('changePercentage')}
                        >
                            <div className="flex items-center justify-end">Chg % <SortIcon field="changePercentage"/></div>
                        </th>

                        {/* Dynamic History Columns - Up to 6 */}
                        {monthHeaders.length > 0 ? (
                            monthHeaders.slice(0, 6).map((header, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-400 font-medium">
                                    {header.split(' ')[0]} <br/> 
                                    <span className="text-[10px] opacity-75">{header.split(' ').slice(1).join(' ')}</span>
                                </th>
                            ))
                        ) : (
                            // Placeholder columns while loading first batch
                            [...Array(6)].map((_, i) => (
                                <th key={i} scope="col" className="px-4 py-3 text-right w-[10%] min-w-[100px] text-gray-300">
                                    M-{i}
                                </th>
                            ))
                        )}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {paginatedData.map((row, idx) => {
                          // Get cached history
                          const history = row.stockPk ? historyCache[row.stockPk] : undefined;
                          const isLoadingHistory = row.stockPk ? loadingHistoryMap[row.stockPk] : false;

                          return (
                          <tr key={idx} className="bg-white hover:bg-gray-50 transition-colors group">
                            <td className="px-4 py-3 font-medium text-gray-900 sticky left-0 bg-white group-hover:bg-gray-50 border-r border-gray-200 z-10 align-top">
                              <div className="flex flex-col gap-1">
                                  <div className="flex items-start gap-2">
                                    <div className="mt-0.5 text-gray-400 flex-shrink-0 w-4">
                                        {row.historyUrl && 
                                         (<a href={row.historyUrl} 
                                         target="_blank" 
                                         rel="noreferrer" 
                                         className="text-gray-400 hover:text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity flex"
                                         onClick={(e) => e.stopPropagation()}>
                                          <History size={14} />
                                          </a>

                                         )
                                        }
                                    </div>
                                    <button 
                                        onClick={() => onSelectStock(row.stockSymbol, row.stockName)}
                                        className="text-indigo-600 hover:text-indigo-800 hover:underline text-left text-sm w-full group/link flex items-center gap-2"
                                    >
                                        <span className="font-semibold break-words line-clamp-2 leading-tight">{row.stockName}</span>
                                        {row.stockUrl && (
                                            <a 
                                                href={row.stockUrl} 
                                                target="_blank" 
                                                rel="noreferrer" 
                                                className="text-gray-400 hover:text-indigo-500 opacity-0 group-hover/link:opacity-100 transition-opacity"
                                                title="View External"
                                                onClick={(e) => e.stopPropagation()}
                                            >
                                                <ExternalLink size={14} />
                                            </a>
                                        )}
                                    </button>
                                  </div>
                                  <div className="flex items-center gap-1 pl-6 mt-1">
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.dColor)}`} title={`Durability: ${row.d}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.vColor)}`} title={`Valuation: ${row.v}`}></div>
                                      <div className={`w-1.5 h-1.5 rounded-full ${getDotColor(row.mColor)}`} title={`Momentum: ${row.m}`}></div>
                                  </div>
                              </div>
                            </td>
                            <td className="px-4 py-3 text-right text-xs align-top">
                                {row.sector}
                            </td>
                            <td className="px-4 py-3 text-right font-mono font-medium text-gray-900 text-sm align-top">
                                {row.percentage.toFixed(2)}%
                            </td>
                            <td className="px-4 py-3 text-right font-mono text-gray-600 text-sm align-top">
                                {(row.quantity / 1000).toLocaleString()} K
                            </td>
                            <td className={`px-4 py-3 text-right font-mono text-sm align-top ${getValueColor(row.changeQuantity)}`}>
                                {row.changeQuantity ? (row.changeQuantity / 1000).toLocaleString() + ' K' : '-'}
                            </td>
                            <td className={`px-4 py-3 text-right font-mono text-sm align-top ${getValueColor(row.changePercentage)}`}>
                                {row.changePercentage ? row.changePercentage.toFixed(2) + '%' : '-'}
                            </td>

                            {/* History Cells */}
                            {[...Array(6)].map((_, hIdx) => {
                                const historyItem = history ? history[hIdx] : null;
                                return (
                                    <td key={hIdx} className="px-4 py-3 text-right font-mono text-sm align-top">
                                        {isLoadingHistory && hIdx === 0 ? (
                                            <div className="flex justify-end"><Loader2 className="animate-spin text-gray-300" size={12}/></div>
                                        ) : historyItem ? (
                                            <span className={getHistoryChangeColor(historyItem.change)}>
                                                {historyItem.change}
                                            </span>
                                        ) : (
                                            <span className="text-gray-300">-</span>
                                        )}
                                    </td>
                                );
                            })}
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
              ) : (
                  <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                      <p>{selectedFund.url ? "No portfolio data found." : "Please select a fund from the Dashboard to view its live portfolio."}</p>
                  </div>
              )}
            </div>

            {/* Pagination Controls */}
            {portfolioData && sortedData.length > 0 && (
              <div className="p-4 bg-gray-50 border-t border-gray-200 flex flex-col sm:flex-row items-center justify-between gap-4">
                <div className="text-xs text-gray-500">
                  Showing {paginatedData.length} of {sortedData.length} holdings
                  {selectedFund.url && " • Data Source: Trendlyne"}
                </div>

                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronLeft size={16} />
                  </button>

                  <span className="text-sm font-medium text-gray-700 px-2">
                    Page {currentPage} of {totalPages}
                  </span>

                  <button
                    onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                    disabled={currentPage === totalPages}
                    className="p-2 rounded-lg border border-gray-200 bg-white text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 transition-colors"
                  >
                    <ChevronRight size={16} />
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default FundView;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Search, TrendingUp, TrendingDown, ArrowRight, ArrowLeft, Upload, Loader2, ExternalLink, History, ChevronLeft, ChevronRight, PieChart as PieIcon, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { FundSnapshot, FundSearchResult, FundPortfolioHolding, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { parseExcelFile, fetchFundPortfolio, fetchFundHoldingHistory } from '../services/dataService';
import FundSearch from './FundSearch';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FundViewProps {
  funds: FundSnapshot[]; // For uploaded files
  onFundDataAdded: (data: FundSnapshot) => void;
  onSelectStock: (symbol: string, name: string) => void;
  initialSelectedFund?: FundSearchResult | null;
}

type SortField = 'percentage' | 'quantity' | 'changeQuantity' | 'changePercentage';
type SortDirection = 'asc' | 'desc';

const ITEMS_PER_PAGE = 50;
const CHART_COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e', '#06b6d4', '#3b82f6', '#64748b'];

const FundView: React.FC<FundViewProps> = ({ funds, onFundDataAdded, onSelectStock, initialSelectedFund }) => {
  const [selectedFund, setSelectedFund] = useState<FundSearchResult | null>(initialSelectedFund || null);

  // Data States
  const [portfolioData, setPortfolioData] = useState<FundPortfolioHolding[] | null>(null);
  const [fundMeta, setFundMeta] = useState<FundMeta | null>(null);
  const [sectorData, setSectorData] = useState<SectorDistribution[]>([]);

  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // History Data State
  const [historyCache, setHistoryCache] = useState<Record<string | number, { date: string, change: string }[]>>({});
  const [monthHeaders, setMonthHeaders] = useState<string[]>([]);
  const [loadingHistoryMap, setLoadingHistoryMap] = useState<Record<string | number, boolean>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('percentage');
  const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  // File Upload State
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync prop changes
  useEffect(() => {
    if (initialSelectedFund) {
      setSelectedFund(initialSelectedFund);
    }
  }, [initialSelectedFund]);

  // Fetch API Data whenever selectedFund changes and has URL
  useEffect(() => {
    const loadData = async () => {
      if (!selectedFund || !selectedFund.url) {
          setPortfolioData(null);
          setFundMeta(null);
          setSectorData([]);
          setHistoryCache({});
          setMonthHeaders([]);
          return;
      }

      setLoading(true);
      try {
        const data = await fetchFundPortfolio(selectedFund.url);
        if (data) {
            setPortfolioData(data.holdings);
            setFundMeta(data.meta);
            setSectorData(data.sectorDistribution);
        } else {
            setPortfolioData([]);
            setFundMeta(null);
            setSectorData([]);
        }
      } catch (err) {
          console.error("Failed to load fund portfolio", err);
          setPortfolioData([]);
      } finally {
          setLoading(false);
      }
    };

    loadData();
  }, [selectedFund]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setIsUploading(true);
      try {
        const data = await parseExcelFile(e.target.files[0]);
        if (data) {
          onFundDataAdded(data);
          // Switch to offline view logic (not fully implemented in this iteration, keeping focus on API)
          setSelectedFund({ name: data.fundName, url: '' });
          alert("Offline file viewing is limited in this demo mode. Please use the API flow.");
        }
      } catch (err) {
        alert("Failed to upload file");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('desc');
    }
  };

  const sortedData = useMemo(() => {
      if (!portfolioData) return [];

      let data = [...portfolioData];
      if (searchTerm) {
          const lower = searchTerm.toLowerCase();
          data = data.filter(item => 
              item.stockName.toLowerCase().includes(lower) || 
              item.stockSymbol.toLowerCase().includes(lower) ||
              item.sector.toLowerCase().includes(lower)
          );
      }

      return data.sort((a, b) => {
          const valA = a[sortField];
          const valB = b[sortField];
          if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
          if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
          return 0;
      });
  }, [portfolioData, searchTerm, sortField, sortDirection]);

  // Pagination Logic
  const totalPages = Math.ceil(sortedData.length / ITEMS_PER_PAGE);
  const paginatedData = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return sortedData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedData, currentPage]);

  // Reset pagination when filter/sort changes
  useEffect(() => {
    setCurrentPage(1);
    // Note: We don't clear historyCache here to preserve loaded data if user navigates back
  }, [searchTerm, sortField, sortDirection, selectedFund]);

  // --- Fetch History for Visible Rows ---
  useEffect(() => {
      if (!fundMeta?.fundPk || !paginatedData.length) return;

      const fetchVisibleHistory = async () => {
          // Identify items that need fetching (have stockPk but no cache)
          const itemsToFetch = paginatedData.filter(item => 
              item.stockPk && !historyCache[item.stockPk] && !loadingHistoryMap[item.stockPk]
          );

          if (itemsToFetch.length === 0) return;

          // Mark as loading
          setLoadingHistoryMap(prev => {
              const next = { ...prev };
              itemsToFetch.forEach(i => { if(i.stockPk) next[i.stockPk] = true; });
              return next;
          });

          // Fetch in batches to avoid overwhelming the browser/proxy
          const BATCH_SIZE = 5;
          for (let i = 0; i < itemsToFetch.length; i += BATCH_SIZE) {
              const batch = itemsToFetch.slice(i, i + BATCH_SIZE);

              await Promise.all(batch.map(async (item) => {
                  if (!item.stockPk) return;
                  try {
                      const url = item.historyUrl ? (item.historyUrl.startsWith('http') ? item.historyUrl : `https://trendlyne.com${item.historyUrl}`) : '';
                      if (!url) return;
                      const history = await fetchFundHoldingHistory(url);
                      if (history && history.length > 0) {
                          // Extract only necessary data: last 6 months
                          const processed = history.slice(0, 6).map(h => ({
                              date: h["Holding Date"],
                              change: h["1M Change %"]
                          }));

                          setHistoryCache(prev => ({
                              ...prev,
                              [item.stockPk!]: processed
                          }));

                          // Update headers if this is the first successful fetch or has newer data
                          setMonthHeaders(prevHeaders => {
                              if (prevHeaders.length === 0 && processed.length > 0) {
                                  return processed.map(p => p.date);
                              }
                              return prevHeaders;
                          });
                      }
                  } catch (e) {
                      console.error(`Failed history fetch for ${item.stockSymbol}`, e);
                  } finally {
                      setLoadingHistoryMap(prev => {
                          const next = { ...prev };
                          if (item.stockPk) delete next[item.stockPk];
                          return next;
                      });
                  }
              }));
          }
      };

      fetchVisibleHistory();
